83c\u3002\u5373\u4f7f\u5f00\u5934\u6b8b\u7559\u4e86\u4e0a\u4e00\u9875\u7684\u95e8\u8bca\u75c5\u5386\u7247\u6bb5\uff08\u5982\u8bca\u65ad\u3001\u5904\u7406\uff09\uff0c\u53ea\u8981\u4e3b\u4f53\u5185\u5bb9\u662f\u8d2d\u836f\u51ed\u8bc1/\u53d6\u836f\u5355\uff0c\u4ecd\u5206\u4e3a MedicationRecord\n- NursingRecord \u2014 \u62a4\u7406\u8bb0\u5f55\n- Other \u2014 \u65e0\u6cd5\u5f52\u7c7b\u7684\u6587\u6863\uff08\u5982\u7eaf\u6536\u8d39\u7968\u636e\u3001\u5e7f\u544a\u7b49\uff09\n\n## \u5173\u952e\u5224\u5b9a\u89c4\u5219\uff08\u5fc5\u987b\u9075\u5b88\uff09\n\n### \u89c4\u52191\uff1a\u6df7\u5408\u5185\u5bb9\u5224\u5b9a\u2014\u2014\u770b\u4e3b\u4f53\u5185\u5bb9\u548c\u4e34\u5e8a\u5b8c\u6574\u6027\n\u5f53\u7247\u6bb5\u540c\u65f6\u5305\u542b\u95e8\u8bca\u75c5\u5386\u8981\u7d20\u548c\u8d2d\u836f/\u53d6\u836f/\u68c0\u9a8c\u4fe1\u606f\u65f6\uff0c\u6309\u4ee5\u4e0b\u89c4\u5219\u5224\u5206\u7c7b\uff1a\n- \u5982\u679c\u7247\u6bb5\u6709**\u5b8c\u6574\u7684\u95e8\u8bca\u5c31\u8bca\u6d41\u7a0b**\uff08\u5c31\u8bca\u65f6\u95f4+\u4e3b\u8bc9+\u73b0\u75c5\u53f2+\u8bca\u65ad+\u5904\u7406\uff09\uff0c\u5373\u4f7f\u9644\u5e26\u4e86\u53d6\u836f\u5355/\u652f\u4ed8\u622a\u56fe/\u68c0\u9a8c\u6570\u636e \u2192 OutpatientRecord\n- \u5982\u679c\u7247\u6bb5\u6709**\u4e3b\u8bc9+\u8bca\u65ad+\u6cbb\u7597\u5904\u7406\u610f\u89c1**\uff0c\u5373\u4f7f\u540e\u9762\u8ddf\u7740\u68c0\u9a8c\u62a5\u544a\u6570\u636e \u2192 OutpatientRecord\uff08\u4e34\u5e8a\u8bca\u7597\u8981\u7d20\u4f18\u5148\u4e8e\u68c0\u9a8c\u6570\u636e\uff09\n- \u5982\u679c\u7247\u6bb5\u6709**\u8bca\u65ad+\u5904\u7406\u63aa\u65bd/\u533b\u5631**\uff08\u542b\u5177\u4f53\u836f\u54c1\u7528\u6cd5\u7528\u91cf\uff09\uff0c\u5373\u4f7f\u8d2d\u836f\u51ed\u8bc1\u7bc7\u5e45\u66f4\u5927 \u2192 OutpatientRecord\uff08\u4e34\u5e8a\u8bca\u7597\u4fe1\u606f\u4e0d\u53ef\u4e22\u5931\uff09\n- \u5982\u679c\u7247\u6bb5\u53ea\u6709**\u5c11\u91cf\u4e0d\u5b8c\u6574\u7684\u4e0a\u9875\u6b8b\u7559**\uff08\u5982\u5355\u72ec\u51e0\u884c\u8bca\u65ad/\u5904\u7406\uff0c\u65e0\u4f53\u683c\u68c0\u67e5\u65e0\u8f85\u52a9\u68c0\u67e5\uff09\uff0c\u800c\u8d2d\u836f\u51ed\u8bc1\u6784\u6210\u72ec\u7acb\u5b8c\u6574\u8bb0\u5f55\uff08\u6709\u72ec\u7acb\u8d2d\u836f\u65f6\u95f4\uff09 \u2192 MedicationRecord\n- \u5982\u679c\u7247\u6bb5\u53ea\u6709\u68c0\u9a8c\u9879\u76ee\u8868\u683c\u6570\u636e\uff08\u9879\u76ee\u540d/\u7ed3\u679c/\u5355\u4f4d/\u53c2\u8003\u533a\u95f4\uff09\uff0c\u6ca1\u6709\u4e3b\u8bc9/\u8bca\u65ad/\u6cbb\u7597\u610f\u89c1 \u2192 LabReport\n\n### \u89c4\u52192\uff1a\u4ee5\u5b9e\u9645\u6570\u636e\u5185\u5bb9\u5224\u5206\u7c7b\uff0c\u4e0d\u4ee5\u6807\u9898/\u5f00\u5934\u6587\u5b57\u4e3a\u51c6\nOCR \u53ef\u80fd\u5728\u9875\u9762\u9876\u90e8\u6df7\u5165\u5176\u4ed6\u6587\u6863\u7684\u6807\u9898\uff08\u5982\"\u51fa\u9662\u8bb0\u5f55\"\u51fa\u73b0\u5728\u68c0\u9a8c\u62a5\u544a\u524d\u9762\uff09\u3002\u5224\u5206\u7c7b\u65f6\u770b\u5b9e\u9645\u6570\u636e\u5185\u5bb9\uff0c\u4e0d\u88ab\u5f00\u5934\u51e0\u4e2a\u5b57\u8bef\u5bfc\u3002\n\n### \u89c4\u52193\uff1a\u65e5\u671f\u63d0\u53d6\u8981\u5b8c\u6574\n\u4ed4\u7ec6\u626b\u63cf\u5168\u6587\u7684\u6240\u6709\"\u5c31\u8bca\u65f6\u95f4\"\u3001\"\u6536\u6b3e\u65e5\u671f\"\u3001\"\u68c0\u9a8c\u65e5\u671f\"\u3001\"\u8d2d\u836f\u65f6\u95f4\"\u7b49\u6807\u8bb0\uff0c\u4e0d\u8981\u9057\u6f0f\u3002\n\n## \u793a\u4f8b\n\n\u8f93\u5165\uff1a\u6d4e\u5b81\u5e02\u7b2c\u4e8c\u4eba\u6c11\u533b\u9662 \u95e8\uff08\u6025\uff09\u8bca\u75c5\u5386 \u5c31\u8bca\u65f6\u95f4\uff1a2023\u5e7409\u670812\u65e5 \u5c31\u8bca\u79d1\u5ba4\uff1a\u5185\u79d1\u95e8\u8bca \u4e3b\u8bc9\uff1a\u819d\u5173\u8282\u75bc\u75db ...\u533b\u751f\u7b7e\u540d\uff1axxx \u6d4e\u5b81\u5e02\u7b2c\u4e8c\u4eba\u6c11\u533b\u9662 \u95e8\uff08\u6025\uff09\u8bca\u75c5\u5386 \u5c31\u8bca\u65f6\u95f4\uff1a2023\u5e7409\u670826\u65e5 \u5c31\u8bca\u79d1\u5ba4\uff1a\u5185\u79d1\u95e8\u8bca \u4e3b\u8bc9\uff1a\u7c7b\u98ce\u6e7f\u6027\u5173\u8282\u708e\u590d\u67e5\n\u8f93\u51fa\uff1a{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-09-12\"