 "ExamReport": "chunks_LabExam", "ImagingReport": "chunks_Imaging", "LabReport": "chunks_LabExam", "MedicationRecord": "chunks_Default", "NursingRecord": "chunks_Clinical", "Other": "chunks_Default", "OutpatientRecord": "chunks_Clinical", "SurgeryRecord": "chunks_Clinical"}, "type_json_key": "type"}}, "downstream": ["Extractor:LabExam", "Extractor:Imaging", "Extractor:Clinical", "Extractor:Default"], "upstream": ["SmartSplitter:MedLink"]}, "Extractor:LabExam": {"obj": {"component_name": "Extractor", "params": {"cite": true, "field_name": "extracted_data_tks", "frequency_penalty": 0.7, "llm_id": "qwen3-max", "max_tokens": 2048, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "presence_penalty": 0.4, "prompts": [{"content": "{ChunkRouter:Router@chunks_LabExam}", "role": "user"}], "sys_prompt": "\u4f60\u662f\u4e00\u4e2a\u533b\u7597\u68c0\u9a8c\u68c0\u67e5\u62a5\u544a\u7ed3\u6784\u5316\u63d0\u53d6\u4e13\u5bb6\u3002\u6839\u636e\u6587\u6863\u5206\u7c7b\u7ed3\u679c\u548c\u539f\u6587\u5185\u5bb9\uff0c\u63d0\u53d6\u7ed3\u6784\u5316\u4e34\u5e8a\u6570\u636e\u3002\n\n## \u4e0a\u6e38\u5206\u7c7b\u7ed3\u679c\n{classify_result_tks}\n\n## \u8f93\u51fa\u683c\u5f0f\n\n\u4e25\u683c\u8f93\u51fa\u7eaf JSON\uff0c\u7981\u6b62\u4f7f\u7528 ```json \u4ee3\u7801\u5757\u5305\u88f9\uff0c\u7981\u6b62\u8f93\u51fa\u4efb\u4f55\u975e JSON \u6587\u5b57\u3002\n\n## \u63d0\u53d6 Schema\uff08LabReport / ExamReport / ImagingReport \u901a\u7528\uff09\n\n{\n  \"report_date\": \"<string|null, \u62a5\u544a\u65e5\u671f YYYY-MM-DD>\",\n  \"items\": [\n    {\n      \"name\": \"<string, \u68c0\u9a8c/\u68c0\u67e5\u9879\u76ee\u540d\u79f0>\",\n      \"value\": \"<string, \u7ed3\u679c\u6570\u503c\uff0c\u539f\u6837\u4fdd\u7559>\",\n      \"unit\": \"<string|null, \u5355\u4f4d>\",\n      \"reference_range\": \"<string|null, \u53c2\u8003\u8303\u56f4>\",\n      \"abnormal\": \"<boolean, \u662f\u5426\u5f02\u5e38>\"\n    }\n  ]\n}\n\n## \u5173\u952e\u7ea6\u675f\n1. \u6240\u6709\u63d0\u53d6\u5b57\u6bb5\u7684