s": ["from", "to", "cc", "bcc", "date", "subject", "body", "attachments"], "output_format": "text", "suffix": ["eml", "msg"]}, "image": {"output_format": "text", "parse_method": "ocr", "suffix": ["jpg", "jpeg", "png", "gif"]}, "pdf": {"lang": "Chinese", "output_format": "json", "parse_method": "paddleocr-vl-1.5@PaddleOCR", "suffix": ["pdf"]}, "slides": {"output_format": "json", "parse_method": "DeepDOC", "suffix": ["pptx", "ppt"]}, "spreadsheet": {"output_format": "html", "parse_method": "DeepDOC", "suffix": ["xls", "xlsx", "csv"]}, "text&markdown": {"output_format": "text", "suffix": ["md", "markdown", "mdx", "txt"]}, "word": {"output_format": "json", "suffix": ["doc", "docx"]}}}}, "upstream": ["File"]}, "SmartSplitter:MedLink": {"downstream": ["ChunkRouter:Router"], "obj": {"component_name": "SmartSplitter", "params": {"classify_field": "classify_result_tks", "llm_id": "deepseek-v3.2", "prompts": [{"content": "{chunks}", "role": "user"}], "sys_prompt": "\u4f60\u662f\u4e00\u4e2a\u533b\u7597\u6587\u6863\u5207\u5206\u4e0e\u5206\u7c7b\u4e13\u5bb6\u3002\u4e0b\u9762\u662f\u4e00\u4efd\u5b8c\u6574\u7684 OCR \u626b\u63cf\u533b\u7597\u6587\u6863\uff0c\u53ef\u80fd\u5305\u542b\u591a\u79cd\u4e0d\u540c\u7c7b\u578b\u7684\u6587\u6863\u5185\u5bb9\u6df7\u6392\u5728\u4e00\u8d77\u3002\n\n**\u91cd\u8981\uff1a\u6587\u6863\u4e2d\u6bcf\u4e2a\u6587\u672c\u5757\u90fd\u6709\u7f16\u53f7\u524d\u7f00 `[BBOX-0]`, `[BBOX-1]`, ... `[BBOX-N]`\uff0c\u8fd9\u662f\u6587\u6863\u7684\u9605\u8bfb\u987a\u5e8f\u7d22\u5f15\u3002**\n\n\u8bf7\u4f60\uff1a\n1. \u6309\u7167\u533b\u7597\u6587\u6863\u7c7b\u578b\u7684\u8bed\u4e49\u8fb9\u754c\u8fdb\u884c\u5207\u5206\u2014\u2014\u6bcf\u4e2a\u7247\u6bb5\u53ea\u5305\u542b\u4e00\u79cd\u6587\u6863\u7c7b\u578b\n2. \u540c\u65f6\u7ed9\u6bcf\u4e2a\u5207\u5206\u7247\u6bb5\u5206\u7c7b\u5e76\u63d0\u53d6\u5143\u6570\u636e\n3. **\u8fd4\u56de\u6bcf\u4e2a\u7247\u6bb5\u7684 bbox \u7d22\u5f15\u8303\u56f4\uff08bbox_start \u548c bbox_end\uff09**\n\n## \u6587\u6863\u7c7b\u578b\u5b9a\u4e49\n\n### OutpatientRecord\uff08\u95e8\u8bca\u75c5\u5386\uff09\n\u5b8c\u6574\u7684\u95e8\u8bca\u5c31\u8bca\u8bb0\u5f55\uff0c\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u5c31\u8bca\u65f6\u95f4 + \u4e3b\u8bc9/\u73b0\u75c5\u53f2/\u8bca\u65ad/\u5904\u7406\u610f\u89c1\u7b49\u4e34\u5e8a\u8981\u7d20\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662\u95e8\u8bca\u75c5\u5386\"\u6216\"\u95e8\u8bca\u590d\u8bca\u75c5\u5386\u8bb0\u5f55\"\u5f00\u5934\n- \u4ece\"\u5c31\u8bca\u65f6\u95f4\"\u5230\"\u533b\u751f\u7b7e\u540d\"\u6216\"\u5904\u7406\u610f\u89c1\"\u7ed3\u675f\u662f\u4e00\u4e2a\u5b8c\u6574\u8bb0\u5f55\n- \u26a0\ufe0f \u95e8\u8bca\u75c5\u5386\u4e2d\u63d0\u5230\u7684\u8f85\u52a9\u68c0\u67e5\u7ed3\u679c\uff08\u5982\"ESR 50mm/h\"\uff09\u662f\u75c5\u5386\u6b63\u6587\u7684\u4e00\u90e8\u5206\uff0c\u4e0d\u8981\u628a\u5b83\u5207\u51fa\u6765\u5f53\u4f5c\u72ec\u7acb\u7684 LabReport\n\n### PrescriptionRecord\uff08\u5904\u65b9\u7528\u836f/\u53d6\u836f\u6267\u884c\u5355\uff09\n\u533b\u9662\u5f00\u5177\u7684\u5904\u65b9\u6216\u53d6\u836f\u6267\u884c\u5355\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u5c31\u8bca\u79d1\u5ba4 + \u5c31\u8bca\u533b\u751f + \u75be\u75c5\u8bca\u65ad + \u836f\u54c1\u7528\u6cd5\u7528\u91cf\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662 \u53d6\u836f\u6267\u884c\u5355\"\u5f00\u5934\n- \u5305\u542b\uff1a\u5c31\u8bca\u79d1\u5ba4\u3001\u5c31\u8bca\u533b\u751f\u3001\u8bca\u65ad\u3001\u836f\u54c1\u540d\u79f0\u3001\u5242\u91cf\u3001\u9891\u6b21\u3001\u7ed9\u836f\u9014\u5f84\n- \u6bcf\u5f20\u72ec\u7acb\u7684\u53d6\u836f\u6267\u884c\u5355/\u5904\u65b9\u662f\u4e00\u4e2a\u7247\u6bb5\n\n\u26a0\ufe0f \u533a\u5206\u8981\u70b9\uff1a\u5982\u679c\u6587\u6863\u542b\u6709\"\u6536\u6b3e\"+\"\u64cd\u4f5c\u5458\"+\"\u51ed\u6761\u4ec5\u4e3a\u2026\u4ea4\u6b3e\u4f9d\u636e\"\u7b49\u4ea4\u6b3e\u51ed\u6761\u7279\u5f81\uff0c\n\u4f46\u7f3a\u5c11\"\u75be\u75c5\u8bca\u65ad\"\u4e14\u65e0\"\u53d6\u836f\u6267\u884c\u5355\"\u6807\u9898 \u2192 \u5e94\u5f52\u4e3a MedicationRecord\uff0c\u4e0d\u662f PrescriptionRecord\u3002\n\u533b\u9662\u7f34\u8d39/\u4ea4\u6b3e\u51ed\u6761\u867d\u7136\u6709\u79d1\u5ba4\u548c\u533b\u751f\u4fe1\u606f\uff0c\u4f46\u672c\u8d28\u662f\u8d2d\u836f\u4ed8\u6b3e\u51ed\u8bc1\u3002\n\n### MedicationRecord\uff08\u8d2d\u836f\u51ed\u8bc1\uff09\n\u836f\u5e97\u6216\u533b\u9662\u8d2d\u836f\u7684\u4ed8\u6b3e\u51ed\u8bc1\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u4ed8\u6b3e\u91d1\u989d + \u836f\u54c1\u6e05\u5355\uff0c\u4f46\u65e0\u533b\u751f\u8bca\u65ad\u548c\u7528\u6cd5\u7528\u91cf\u3002\n- \u836f\u623f/\u836f\u5e97\u8d2d\u836f\u5c0f\u7968\uff1a\u542b\u836f\u5355\u7f16\u53f7\u3001\u6536\u94f6\u5458\u3001\u54c1\u540d\u3001\u89c4\u683c\u3001\u96f6\u552e\u4ef7\u3001\u6570\u91cf\u3001\u5e94\u6536\u91d1\u989d\n- \u533b\u9662\u6536\u8d39\u7968\u636e\uff1a\u542b\"\u6536\u8d39\u5458\"\"\u6536\u6b3e\"\u5b57\u6837\n- **\u5207\u5206\u89c4\u5219\uff08\u5f3a\u5236\uff09**\uff1a\n  - \u6309\u8d2d\u836f\u65e5\u671f\u5207\u5206\uff0c\u6bcf\u4e2a\u4e0d\u540c\u65e5\u671f\u7684\u8d2d\u836f\u51ed\u8bc1\u5fc5\u987b\u662f\u72ec\u7acb\u7684 segment\n  - \u5173\u952e\u8bc6\u522b\u7279\u5f81\uff1a\u8d2d\u836f\u65f6\u95f4\uff08YYYY-MM-DD HH:MM:SS\uff09\u3001\u836f\u5355\u7f16\u53f7\u3001\u836f\u5e97\u540d\u79f0\n  - \u5373\u4f7f\u4e24\u5f20\u8d2d\u836f\u51ed\u8bc1\u5728\u7269\u7406\u9875\u9762\u4e0a\u8fde\u7eed\uff0c\u53ea\u8981\u8d2d\u836f\u65f6\u95f4\u4e0d\u540c\uff0c\u5fc5\u987b\u5206\u4e3a\u4e24\u4e2a segment\n  - \u6bcf\u4e2a segment \u53ea\u5305\u542b\u4e00\u4e2a\u8d2d\u836f\u65f6\u95f4\u70b9\u7684\u8bb0\u5f55\n\n### LabReport\uff08\u68c0\u9a8c\u62a5\u544a\uff09\n\u533b\u9662\u68c0\u9a8c\u79d1\u51fa\u5177\u7684\u68c0\u9a8c\u62a5\u544a\u5355\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u68c0\u9a8c\u9879\u76ee + \u68c0\u9a8c\u7ed3\u679c + \u53c2\u8003\u8303\u56f4\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662\u68c0\u9a8c\u62a5\u544a\u5355\"\u6216\u76f4\u63a5\u4ee5\u68c0\u9a8c\u9879\u76ee\u8868\u683c\u5f00\u5934\n- \u5305\u542b\u591a\u4e2a\u68c0\u9a8c\u6307\u6807\u548c\u53c2\u8003\u8303\u56f4\n\n### DischargeRecord\uff08\u51fa\u9662\u8bb0\u5f55/\u51fa\u9662\u5c0f\u7ed3\uff09\n\u4f4f\u9662\u51fa\u9662\u8bb0\u5f55\u6216\u51fa\u9662\u5c0f\u7ed3\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u51fa\u9662\u8bca\u65ad + \u51fa\u9662\u533b\u5631 + \u4f4f\u9662\u7ecf\u8fc7\u3002\n- \u5373\u4f7f\u5305\u542b\u68c0\u9a8c\u6570\u636e\uff08\u5982ESR\u3001CRP\u7b49\u6570\u503c\uff09\uff0c\u53ea\u8981\u6709\"\u51fa\u9662\u8bca\u65ad\"\u548c\"\u51fa\u9662\u533b\u5631\"\u2192 DischargeRecord\n\n### AdmissionRecord\uff08\u5165\u9662\u8bb0\u5f55\uff09\n\u4f4f\u9662\u5165\u9662\u8bb0\u5f55\u6216\u4f4f\u9662\u75c5\u5386\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u5165\u9662\u65f6\u95f4 + \u4e3b\u8bc9 + \u73b0\u75c5\u53f2 + \u8be6\u7ec6\u4f53\u683c\u68c0\u67e5 + \u521d\u6b65\u8bca\u65ad\u3002\n- \u901a\u5e38\u4ee5\"\u5165\u9662\u8bb0\u5f55\"\u6216\"\u4f4f\u9662\u75c5\u5386\"\u6807\u9898\u5f00\u5934\n- \u5305\u542b\u5b8c\u6574\u4f53\u683c\u68c0\u67e5\uff08\u4f53\u6e29/\u8109\u640f/\u547c\u5438/\u8840\u538b + \u5934\u9888\u5fc3\u80ba\u8179\u56db\u80a2\u795e\u7ecf\u7cfb\u7edf\u9010\u4e00\u68c0\u67e5\uff09\u548c\u521d\u6b65\u8bca\u65ad\n- \u533a\u522b\u4e8e\u95e8\u8bca\u75c5\u5386\uff1a\u5165\u9662\u8bb0\u5f55\u6709\u5b8c\u6574\u7684\u7cfb\u7edf\u4f53\u683c\u68c0\u67e5\u3001\u4e2a\u4eba\u53f2\u3001\u5a5a\u80b2\u53f2\u3001\u5bb6\u65cf\u53f2\uff0c\u95e8\u8bca\u75c5\u5386\u901a\u5e38\u6ca1\u6709\n- \u533a\u522b\u4e8e\u51fa\u9662\u8bb0\u5f55\uff1a\u5165\u9662\u8bb0\u5f55\u6709\"\u521d\u6b65\u8bca\u65ad\"\uff08\u65e0\"\u51fa\u9662\u8bca\u65ad\"\uff09\uff0c\u6709\u4f53\u683c\u68c0\u67e5\uff08\u65e0\"\u8bca\u7597\u7ecf\u8fc7\"\u548c\"\u51fa\u9662\u533b\u5631\"\uff09\n- \u5165\u9662\u8bb0\u5f55\u53ef\u80fd\u8de8\u8d8a\u591a\u9875\uff0c\u4e0d\u8981\u62c6\u5f00\uff08\u4ece\u5165\u9662\u4fe1\u606f\u5230\u521d\u6b65\u8bca\u65ad\u662f\u4e00\u4e2a\u5b8c\u6574\u8bb0\u5f55\uff09\n\n### ExaminationReport\uff08\u68c0\u67e5\u62a5\u544a\uff09\n\u5f71\u50cf\u68c0\u67e5\u3001\u5fc3\u7535\u56fe\u3001\u8d85\u58f0\u3001CT/MRI\u3001\u75c5\u7406\u68c0\u67e5\u7b49\u8f85\u52a9\u68c0\u67e5\u62a5\u544a\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u68c0\u67e5\u65e5\u671f + \u68c0\u67e5\u6240\u89c1/\u5f71\u50cf\u8868\u73b0 + \u68c0\u67e5\u7ed3\u8bba/\u610f\u89c1\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662\u68c0\u67e5\u62a5\u544a\"\u3001\"\u5f71\u50cf\u62a5\u544a\"\u3001\"\u75c5\u7406\u68c0\u67e5\u62a5\u544a\u5355\"\u3001\"\u533b\u5b66\u5f71\u50cf\u68c0\u67e5\u62a5\u544a\u5355\"\u3001\"\u5fc3\u7535\u56fe\u62a5\u544a\"\u5f00\u5934\n- \u5305\u542b\u68c0\u67e5\u6240\u89c1\uff08\u5f71\u50cf\u8868\u73b0/\u5927\u4f53\u68c0\u67e5/\u955c\u4e0b\u6240\u89c1\uff09\u548c\u68c0\u67e5\u7ed3\u8bba\uff08\u610f\u89c1/\u8bca\u65ad\u610f\u89c1/\u75c5\u7406\u8bca\u65ad\uff09\n- \u540c\u4e00\u4efd\u68c0\u67e5\u62a5\u544a\uff08\u542b\u591a\u9875\uff09\u4e0d\u8981\u62c6\u5f00\n- \u26a0\ufe0f \u533a\u5206\u4e8e LabReport\uff1aLabReport \u662f\u68c0\u9a8c\u62a5\u544a\uff0c\u6709\u68c0\u9a8c\u9879\u76ee+\u6570\u503c+\u53c2\u8003\u8303\u56f4\u7684\u8868\u683c\u7ed3\u6784\uff1bExaminationReport \u662f\u68c0\u67e5\u62a5\u544a\uff0c\u4ee5\u53d9\u8ff0\u6027\u63cf\u8ff0\u4e3a\u4e3b\n\n## \u5ffd\u7565\u7684\u5185\u5bb9\uff08\u4e0d\u5207\u5206\u3001\u4e0d\u8f93\u51fa\uff09\n\u4ee5\u4e0b\u5185\u5bb9\u4e0d\u5c5e\u4e8e\u4e34\u5e8a\u533b\u7597\u6587\u6863\uff0c\u76f4\u63a5\u8df3\u8fc7\uff0c\u4e0d\u8981\u4e3a\u5176\u751f\u6210\u5207\u5206\u7247\u6bb5\uff1a\n- \u5fae\u4fe1/\u652f\u4ed8\u5b9d\u652f\u4ed8\u51ed\u8bc1\uff08OCR \u6587\u672c\u5305\u542b\"\u652f\u4ed8\u6210\u529f\"+\"\u4ea4\u6613\u5355\u53f7\"+\"\u8d22\u4ed8\u901a\u652f\u4ed8\u79d1\u6280\u6709\u9650\u516c\u53f8\"\u6216\"\u652f\u4ed8\u5b9d\"\u7b49\u5173\u952e\u8bcd\uff0c\u4f46\u4e0d\u5305\u542b\u836f\u54c1\u540d\u79f0\u3001\u89c4\u683c\u3001\u6570\u91cf\u3001\u5355\u4ef7\uff09\n- \u533b\u9662\u6536\u8d39\u7968\u636e/\u53d1\u7968\uff08\u542b\u5927\u5199\u91d1\u989d\u3001\u53d1\u7968\u53f7\uff0c\u65e0\u836f\u54c1\u7528\u6cd5\u7528\u91cf\uff09\n- \u4e34\u5e8a\u7167\u7247\uff08\u60a3\u8005\u624b/\u8db3/\u5173\u8282\u7b49\u7167\u7247\u9875\uff0c\u65e0\u6587\u5b57\u5185\u5bb9\u6216\u4ec5\u6709\u5c11\u91cf OCR \u788e\u7247\uff09\n\n## \u8f93\u51fa\u683c\u5f0f\n\u4e25\u683c\u8f93\u51fa\u7eaf JSON \u6570\u7ec4\uff0c\u683c\u5f0f\uff1a[{...}, {...}, ...]\uff0c\u7981\u6b62 ```json \u4ee3\u7801\u5757\u3002\u6bcf\u4e2a\u5143\u7d20\uff1a\n{\n  \"type\": \"<\u6587\u6863\u7c7b\u578b>\",\n  \"bbox_start\": <\u8d77\u59cb bbox \u7f16\u53f7>,\n  \"bbox_end\": <\u7ed3\u675f bbox \u7f16\u53f7>,\n  \"row_start\": <\u8868\u683c\u5185\u8d77\u59cb\u884c\u53f7\uff08\u53ef\u9009\uff09>,\n  \"row_end\": <\u8868\u683c\u5185\u7ed3\u675f\u884c\u53f7\uff08\u53ef\u9009\uff09>,\n  \"encounter_dates\": [\"YYYY-MM-DD\"],\n  \"department\": \"<\u79d1\u5ba4\u540d\u79f0|null>\",\n  \"record_count\": 1\n}\n\n**bbox_start \u548c bbox_end \u662f\u6574\u6570\uff0c\u8868\u793a\u8be5\u7247\u6bb5\u5305\u542b\u7684 bbox \u7d22\u5f15\u8303\u56f4\uff08inclusive\uff09\u3002**\n\u4f8b\u5982\uff1a`\"bbox_start\": 0, \"bbox_end\": 5` \u8868\u793a\u8be5\u7247\u6bb5\u5305\u542b [BBOX-0] \u5230 [BBOX-5] \u7684\u6240\u6709\u6587\u672c\u5757\u3002\n\n**row_start \u548c row_end\uff08\u53ef\u9009\uff09\uff1a** \u5f53\u4e00\u4e2a\u8868\u683c bbox \u5185\u5305\u542b\u591a\u4e2a\u72ec\u7acb\u8bb0\u5f55\u65f6\u4f7f\u7528\u3002\n- \u8868\u683c\u884c\u6709 [BBOX-N-R0], [BBOX-N-R1], ... \u6807\u8bb0\n- row_start/row_end \u6307\u5b9a\u8be5\u7247\u6bb5\u5728\u8868\u683c\u5185\u7684\u884c\u8303\u56f4\uff08inclusive\uff09\n- \u4f8b\u5982\uff1a\u4e00\u4e2a\u8868\u683c [BBOX-415] \u5305\u542b\u4e24\u5f20\u8d2d\u836f\u5c0f\u7968\uff0c\u7b2c\u4e00\u5f20\u662f R0-R24\uff0c\u7b2c\u4e8c\u5f20\u662f R25-R49\n  \u2192 \u7b2c\u4e00\u4e2a\u7247\u6bb5\uff1a{\"bbox_start\": 415, \"bbox_end\": 415, \"row_start\": 0, \"row_end\": 24}\n  \u2192 \u7b2c\u4e8c\u4e2a\u7247\u6bb5\uff1a{\"bbox_start\": 415, \"bbox_end\": 415, \"row_start\": 25, \"row_end\": 49}\n- \u5982\u679c\u8868\u683c\u53ea\u6709\u4e00\u4e2a\u8bb0\u5f55\uff08\u4e0d\u9700\u8981\u62c6\u5206\uff09\uff0c\u4e0d\u9700\u8981\u8fd4\u56de row_start/row_end\n- \u5982\u679c bbox \u4e0d\u662f\u8868\u683c\uff08\u6ca1\u6709 R \u6807\u8bb0\uff09\uff0c\u4e0d\u9700\u8981\u8fd4\u56de row_start/row_end\n\n## \u5207\u5206\u89c4\u5219\n1. \u6bcf\u6b21\u95e8\u8bca\u5c31\u8bca\u662f\u4e00\u4e2a\u72ec\u7acb\u7247\u6bb5\u3002\u4ece\"\u5c31\u8bca\u65f6\u95f4\"\u5230\"\u5904\u7406\u610f\u89c1/\u533b\u751f\u7b7e\u540d\"\u662f\u4e00\u4e2a\u5b8c\u6574\u8bb0\u5f55\u2014\u2014\u4e0d\u8981\u62c6\u5f00\uff0c\u4e5f\u4e0d\u8981\u628a\u4e0d\u540c\u65e5\u671f\u7684\u591a\u6b21\u5c31\u8bca\u5408\u5e76\n2. \u68c0\u9a8c\u62a5\u544a\u6309\"\u68c0\u9a8c\u65e5\u671f + \u62a5\u544a\u5355\"\u5207\u5206\u2014\u2014\u6bcf\u4efd\u72ec\u7acb\u7684\u68c0\u9a8c\u62a5\u544a\u5355\u662f\u4e00\u4e2a\u7247\u6bb5\uff08\u5982\uff1a\u8840\u5e38\u89c4\u62a5\u544a\u5355\u3001\u809d\u529f\u80fd\u62a5\u544a\u5355\u3001\u8840\u6c89\u62a5\u544a\u5355\u5404\u81ea\u72ec\u7acb\uff09\uff1b\u540c\u4e00\u4efd\u62a5\u544a\u5355\u542b\u591a\u9875\u8868\u683c\u65f6\u4e0d\u8981\u62c6\u5f00\n3. \u8d2d\u836f\u51ed\u8bc1\u548c\u53d6\u836f\u6267\u884c\u5355\u5404\u81ea\u72ec\u7acb\u2014\u2014\u6bcf\u5f20\u7968\u636e/\u6267\u884c\u5355\u662f\u4e00\u4e2a\u72ec\u7acb\u7247\u6bb5\uff08\u4e0d\u540c\u65e5\u671f\u6216\u4e0d\u540c\u5355\u53f7 = \u4e0d\u540c\u7247\u6bb5\uff09\uff0c\u4e8c\u8005\u662f\u4e0d\u540c\u7684 type\n4. \u51fa\u9662\u8bb0\u5f55\u4e0d\u8981\u62c6\u5f00\n5. \u5982\u679c\u6587\u6863\u672b\u5c3e\u6709\u51e0\u4e2a\u5b57\u7684\u6b8b\u7559\u788e\u7247\uff08<50\u5b57\uff09\uff0c\u5408\u5e76\u5230\u524d\u4e00\u4e2a\u7247\u6bb5\n6. \u5982\u679c\u4e00\u4e2a\u8868\u683c bbox \u5185\u5305\u542b\u591a\u4e2a\u72ec\u7acb\u8bb0\u5f55\uff08\u5982\u4e24\u5f20\u8d2d\u836f\u5c0f\u7968\u3001\u4e24\u4efd\u68c0\u9a8c\u62a5\u544a\uff09\uff0c\u7528 row_start/row_end \u6307\u5b9a\u6bcf\u4e2a\u8bb0\u5f55\u7684\u884c\u8303\u56f4\uff0c\u800c\u4e0d\u662f\u628a\u6574\u4e2a\u8868\u683c\u4f5c\u4e3a\u4e00\u4e2a\u7247\u6bb5\u3002\u884c\u53f7\u53c2\u8003\u8868\u683c\u5185\u7684 [BBOX-N-Rn] \u6807\u8bb0\u3002\n\n## OCR \u5e38\u89c1\u8bef\u8bc6\u522b\u7ea0\u6b63\uff08\u5207\u5206\u548c\u5206\u7c7b\u65f6\u53c2\u8003\uff09\nOCR \u626b\u63cf\u53ef\u80fd\u5bfc\u81f4\u836f\u54c1\u540d\u79f0\u8bc6\u522b\u9519\u8bef\uff0c\u4ee5\u4e0b\u662f\u672c\u6570\u636e\u96c6\u5e38\u89c1\u7684 OCR \u9519\u8bef\uff0c\u5207\u5206\u65f6\u8bf7\u6ce8\u610f\uff1a\n- \"\u963f\u8fd0\u6728\u5355\u6297\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u963f\u8fbe\u6728\u5355\u6297\"\uff08adalimumab\uff09\n- \"\u6765\u6c1f\u672a\u80fa\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u6765\u6c1f\u7c73\u7279\"\uff08leflunomide\uff09\n- \"\u7532\u6c28\u558b\u5464\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u7532\u6c28\u8776\u5464\"\uff08methotrexate\uff09\n- \"\u585e\u6765\u6614\u5e03\u80fa\u56ca\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u585e\u6765\u6614\u5e03\u80f6\u56ca\"\uff08celecoxib\uff09\n- \"\u7c7b\u98ce\u663e\u6027\u5173\u8282\u708e\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u7c7b\u98ce\u6e7f\u6027\u5173\u8282\u708e\"\uff08rheumatoid arthritis\uff09\n- \"\u7f8e\u6d1b\u6614\u5e9a\" \u2192 \u5e94\u7406\u89e3\u4e3a\"\u7f8e\u6d1b\u6614\u5eb7\"\uff08meloxicam\uff09\n\n\u7ea0\u6b63\u539f\u5219\uff1a\n1. \u4ec5\u7ea0\u6b63\u9ad8\u7f6e\u4fe1\u5ea6\u7684\u6807\u51c6\u533b\u5b66\u672f\u8bed\n2. \u4e0d\u786e\u5b9a\u7684\u4e0d\u8981\u7ea0\u6b63\n3. \u7ea0\u6b63\u540e\u7684\u6587\u672c\u5e94\u4fdd\u6301\u539f\u6587\u7684\u8bed\u4e49\u548c\u7ed3\u6784\n\n## \u65e5\u671f\u63d0\u53d6\u89c4\u5219\n- \u4ece\u6587\u672c\u4e2d\u63d0\u53d6\u5b9e\u9645\u65e5\u671f\uff0c\u683c\u5f0f YYYY-MM-DD\n- \u5982\u679c\u65e5\u671f\u65e0\u6cd5\u8bc6\u522b\uff08OCR\u635f\u574f\uff09\uff0c\u4f7f\u7528\u7a7a\u6570\u7ec4 []\n- \u4e0d\u8981\u731c\u6d4b\u65e5\u671f", "temperature": 0, "temperatureEnabled": false}}, "upstream": ["Parser:MedLink"]}, "Tokenizer:MedEmbed": {"downstream": ["Invoke:SyncChunks"], "obj": {"component_name": "Tokenizer", "params": {"fields": ["text"], "filename_embd_weight