d6\uff1a\n- admission_date: \u5165\u9662\u65e5\u671f\n- discharge_date: \u51fa\u9662\u65e5\u671f\n- admission_diagnosis: \u5165\u9662\u8bca\u65ad\n- discharge_diagnosis: \u51fa\u9662\u8bca\u65ad\n- treatment_summary: \u6cbb\u7597\u7ecf\u8fc7\n- discharge_instructions: \u51fa\u9662\u533b\u5631\n\n\u3010\u5982\u679c\u662f \u68c0\u9a8c\u62a5\u544a LabReport\u3011\u63d0\u53d6\uff1a\n- report_date: \u62a5\u544a\u65e5\u671f\n- items: [{\"name\": \"\u68c0\u9a8c\u9879\u76ee\", \"value\": \"\u6570\u503c\", \"unit\": \"\u5355\u4f4d\", \"reference_range\": \"\u53c2\u8003\u8303\u56f4\", \"abnormal\": true/false}]\n\u6ce8\u610f\uff1a\u5ffd\u7565\u91cd\u590d\u7684\u8868\u5934\u884c\uff0c\u6bcf\u4e2a\u68c0\u9a8c\u9879\u76ee\u72ec\u7acb\u63d0\u53d6\u3002\n\n\u3010\u5982\u679c\u662f \u68c0\u67e5\u62a5\u544a ExamReport\u3011\u63d0\u53d6\uff1a\n- exam_type: \u68c0\u67e5\u7c7b\u578b\n- exam_date: \u68c0\u67e5\u65e5\u671f\n- findings: \u68c0\u67e5\u6240\u89c1\n- conclusion: \u68c0\u67e5\u7ed3\u8bba\n\n\u3010\u5982\u679c\u662f \u5f71\u50cf\u62a5\u544a ImagingReport\u3011\u63d0\u53d6\uff1a\n- imaging_type: \u5f71\u50cf\u7c7b\u578b\uff08CT/MRI/X\u5149\u7b49\uff09\n- exam_date: \u68c0\u67e5\u65e5\u671f\n- findings: \u5f71\u50cf\u6240\u89c1\n- conclusion: \u5f71\u50cf\u7ed3\u8bba\n\n\u3010\u5982\u679c\u662f \u624b\u672f\u8bb0\u5f55 SurgeryRecord\u3011\u63d0\u53d6\uff1a\n- surgery_date: \u624b\u672f\u65e5\u671f\n- surgery_name: \u624b\u672f\u540d\u79f0\n- surgeon: \u4e3b\u5200\u533b\u751f\n- anesthesia: \u9ebb\u9189\u65b9\u5f0f\n- procedure: \u624b\u672f\u7ecf\u8fc7\n- findings: \u672f\u4e2d\u6240\u89c1\n\n\u3010\u5982\u679c\u662f \u7528\u836f\u8bb0\u5f55 MedicationRecord\u3011\u63d0\u53d6\uff1a\n- medications: [{\"name\": \"\u836f\u54c1\u540d\", \"dosage\": \"\u5242\u91cf\", \"frequency\": \"\u9891\u6b21\", \"route\": \"\u7ed9\u836f\u9014\u5f84\", \"start_date\": \"\u5f00\u59cb\u65e5\u671f\"}]\n\n\u3010\u5982\u679c\u662f \u62a4\u7406\u8bb0\u5f55 NursingRecord\u3011\u63d0\u53d6\uff1a\n- record_date: \u8bb0\u5f55\u65e5\u671f\n- vital_signs: \u751f\u547d\u4f53\u5f81\n- nursing_assessment: \u62a4\u7406\u8bc4\u4f30\n- nursing_actions: \u62a4\u7406\u63aa\u65bd\n\n\u3010\u5982\u679c\u662f \u5176\u4ed6 Other\u3011\u63d0\u53d6\uff1a\n- content_summary: \u5185\u5bb9\u6458\u8981\n\n\u53ea\u8f93\u51fa JSON\uff0c\u4e0d\u8981\u5176\u4ed6\u6587\u5b57\u3002\u5982\u679c\u67d0\u5b57\u6bb5\u5728\u6587\u672c\u4e2d\u4e0d\u5b58\u5728\uff0c\u8bbe\u4e3a null\u3002", "prompts": "{Extractor:Classify@chunks}", "temperature": 0.1, "top_p": 0.3, "max_tokens": 2048, "presence_penalty": 0.4, "frequency_penalty": 0.7, "cite": true, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}}}, "sourcePosition": "right", "targetPosition": "left"}, {"id": "Extractor:Critique", "type": "contextNode", "position": {"x": 1400, "y": 200}, "data": {"label": "Extractor", "name": "Critique", "form": {"field_name": "critique_result_kwd", "llm_id": "deepseek-v3.2", "sys_prompt": "\u4f60\u662f\u4e00\u4e2a\u533b\u7597\u4fe1\u606f\u5ba1\u6838\u4e13\u5bb6\u3002\u5bf9\u6bd4\u539f\u6587\u548c\u63d0\u53d6\u7ed3\u679c\uff0c\u5224\u65ad\u63d0\u53d6\u8d28\u91cf\u3002\n\n\u539f\u6587\u5728 chunk \u7684 text \u5185\u5bb9\u4e2d\u3002\n\u63d0\u53d6\u7ed3\u679c\u5728 extracted_data_tks \u5b57\u6bb5\u4e2d\u3002\n\n\u8bf7\u5ba1\u6838\u63d0\u53d6\u7ed3\u679c\u662f\u5426\u51c6\u786e\u53cd\u6620\u4e86\u539f\u6587\u5185\u5bb9\uff1a\n- CONFIRMED\uff1a\u63d0\u53d6\u7ed3\u679c\u5b8c\u5168\u51c6\u786e\uff0c\u4e0e\u539f\u6587\u4e00\u81f4\n- UNCERTAIN\uff1a\u90e8\u5206\u4fe1\u606f\u53ef\u80fd\u4e0d\u51c6\u786e\u6216\u5b58\u5728\u6b67\u4e49\n- HALLUCINATED\uff1a\u63d0\u53d6\u7ed3\u679c\u5305\u542b\u539f\u6587\u4e2d\u4e0d\u5b58\u5728\u7684\u4fe1\u606f\n\n\u53ea\u8f93\u51fa\u4e00\u4e2a\u8bcd\uff1aCONFIRMED \u6216 UNCERTAIN \u6216 HALLUCINATED", "prompts": "{Extractor:Extract@chunks}", "temperature": 0.1, "top_p": 0.3, "max_tokens": 32, "presence_penalty": 0.4, "frequency_penalty": 0.7, "cite": true, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}}}, "sourcePosition": "right", "targetPosition": "left"}, {"id": "Tokenizer:MedEmbed", "type": "tokenizerNode", "position": {"x": 1670, "y": 200}, "data": {"label": "Tokenizer", "name": "Tokenizer_0", "form": {"search_method": ["full_text", "embedding"], "filename_embd_weight": 0.1, "fields": ["text"], "outputs": {}}}, "sourcePosition": "right", "targetPosition": "left"}], "edges": [{"id": "xy-edge__Filestart-Parser:MedLinkend", "source": "File", "target": "Parser:MedLink", "sourceHandle": "start", "targetHandle": "end"}, {"id": "xy-edge__Parser:MedLinkstart-Splitter:MedLinkend", "source": "Parser:MedLink", "target": "Splitter:MedLink", "sourceHandle": "start", "targetHandle": "end"}, {"id": "xy-edge__Splitter:MedLinkstart-Extractor:Classifyend", "source": "Splitter:MedLink", "target": "Extractor:Classify", "sourceHandle": "start", "targetHandle": "end"}, {"id": "xy-edge__Extractor:Classifystart-Extractor:Extractend", "source": "Extractor:Classify", "target": "Extractor:Extract", "sourceHandle": "start", "targetHandle": "end"}, {"id": "xy-edge__Extractor:Extractstart-Extractor:Critiqueend", "source": "Extractor:Extract", "target": "Extractor:Critique", "sourceHandle": "start", "targetHandle": "end"}, {"id": "xy-edge__Extractor:Critiquestart-Tokenizer:MedEmbedend", "source": "Extractor:Critique", "target": "Tokenizer:MedEmbed", "sourceHandle": "start", "targetHandle": "end"}]}, "history": [], "messages": [], "path": [], "retrieval": [], "variables": {}}', false);
INSERT INTO "user_canvas_version" ("id", "create_time", "create_date", "update_time", "update_date", "user_canvas_id", "title", "description", "dsl", "release") VALUES ('e6a8e85b2b7d402d8aa35865e9919ea5', 1773027287611, '2026-03-09T11:35:00'::timestamp, 1773027287611, '2026-03-09T11:35:00'::timestamp, 'a445e54a1a3311f1a5992a5fbb884ed3', 'MedLinkAI_Pipeline_v1.6_no_critique_2026_03_09_11_35', NULL, '{"components": {"File": {"obj": {"component_name": "File", "params": {}}, "downstream": ["Parser:MedLink"], "upstream": []}, "Parser:MedLink": {"obj": {"component_name": "Parser", "params": {"outputs": {"html": {"type": "string", "value": ""}, "json": {"type": "Array<object>", "value": []}, "markdown": {"type": "string", "value": ""}, "text": {"type": "string", "value": ""}}, "setups": {"pdf": {"output_format": "json", "suffix": ["pdf"], "parse_method": "DeepDOC"}, "spreadsheet": {"output_format": "html", "suffix": ["xls", "xlsx", "csv"], "parse_method": "DeepDOC"}, "image": {"output_format": "text", "suffix": ["jpg", "jpeg", "png", "gif"], "parse_method": "ocr"}, "word": {"output_format": "json", "suffix": ["doc", "docx"]}, "slides": {"output_format": "json", "suffix": ["pptx", "ppt"], "parse_method": "DeepDOC"}, "text&markdown": {"output_format": "text", "suffix": ["md", "markdown", "mdx", "txt"]}, "email": {"output_format": "text", "suffix": ["eml", "msg"], "fields": ["from", "to", "cc", "bcc", "date", "subject", "body", "attachments"]}}}}, "downstream": ["Splitter:MedLink"], "upstream": ["File"]}, "Splitter:MedLink": {"obj": {"component_name": "Splitter", "params": {"children_delimiters": [], "chunk_token_size": 1024, "delimiters": ["\n"], "enable_children": false, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "overlapped_percent": 0, "table_context_size": 0, "image_context_size": 0}}, "downstream": ["Extractor:Classify"], "upstream": ["Parser:MedLink"]}, "Extractor:Classify": {"obj": {"component_name": "Extractor", "params": {"cite": true, "field_name": "classify_result_tks", "frequency_penalty": 0.7, "llm_id": "deepseek-v3.2", "max_tokens": 256, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "presence_penalty": 0.4, "prompts": [{"content": "{Splitter:MedLink@chunks}", "role": "user"}], "sys_prompt": "你是一个医疗文档分类专家。根据以下医疗文档片段，提取文档类型、就诊日期和科室信息。\n\n## 输出格式\n\n严格输出纯 JSON，禁止使用 ```json 代码块包裹，禁止输出任何非 JSON 文字。\n\n## JSON Schema\n\n{\n  \"type\": \"<string, 必填, 枚举值见下方>\",\n  \"record_count\": <integer, 该片段中包含的独立记录条数>,\n  \"encounter_dates\": [\"<YYYY-MM-DD>\", ...],\n  \"department\": \"<string|null, 就诊科室>\"\n}\n\n## type 枚举值（必须使用英文值，禁止使用中文）\n\n- OutpatientRecord — 门诊病历（含复诊记录）\n- AdmissionRecord — 入院记录\n- DischargeRecord — 出院小结/出院记录\n- LabReport — 检验报告（血常规、生化、免疫等）\n- ExamReport — 检查报告（心电图、B超等）\n- ImagingReport — 影像报告（X光、CT、MRI等）\n- SurgeryRecord — 手术记录\n- MedicationRecord — 用药记录/处方/购药凭证/取药单\n- NursingRecord — 护理记录\n- Other — 无法归类的文档（如纯收费票据、广告等）\n\n## 字段提取规则\n\n1. record_count：统计片段中包含的独立记录条数。每个独立的就诊时间、检验报告、购药凭证算一条。仔细查找所有\"就诊时间\"、\"收款日期\"等标记来计数。\n2. encounter_dates：提取所有独立记录的日期，格式 YYYY-MM-DD，按时间顺序排列。如果某条记录无日期则跳过该条。\n3. department：提取科室名称。无法确定则填 null。\n\n## 示例\n\n输入：济宁市第二人民医院 门（急）诊病历 就诊时间：2023年09月12日 就诊科室：内科门诊 主诉：膝关节疼痛 ...医生签名：xxx 济宁市第二人民医院 门（急）诊病历 就诊时间：2023年09月26日 就诊科室：内科门诊 主诉：类风湿性关节炎复查\n输出：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-09-12\", \"2023-09-26\"], \"department\": \"内科门诊\"}\n\n输入：菏泽市定陶区人民医院检验报告单 血沉 44.00 mm/h 0~20\n输出：{\"type\": \"LabReport\", \"record_count\": 1, \"encounter_dates\": [], \"department\": null}\n\n输入：幸福人大药房 收款日期：2024-09-08 甲氨蝶呤片 2.5mg*16片 67.0元 ...购药凭证 收款日期：2024-10-28 甲氨蝶呤片 2.5mg*16片 67.0元\n输出：{\"type\": \"MedicationRecord\", \"record_count\": 2, \"encounter_dates\": [\"2024-09-08\", \"2024-10-28\"], \"department\": null}\n\n输入：济宁市第二人民医院 门（急）诊病历 就诊时间：2023年10月10日 就诊科室：内科门诊 主诉：类风湿性关节炎复查 ...医生签名：xxx 就诊时间：2023年10月24日 就诊科室：内科门诊 主诉：类风湿性关节炎复查 ...医生签名：xxx\n输出：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-10-10\", \"2023-10-24\"], \"department\": \"内科门诊\"}", "temperature": 0.1, "top_p": 0.3}}, "downstream": ["Extractor:Extract"], "upstream": ["Splitter:MedLink"]}, "Extractor:Extract": {"obj": {"component_name": "Extractor", "params": {"cite": true, "field_name": "extracted_data_tks", "frequency_penalty": 0.7, "llm_id": "qwen3-max", "max_tokens": 2048, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "presence_penalty": 0.4, "prompts": [{"content": "{Extractor:Classify@chunks}", "role": "user"}], "sys_prompt": "你是一个医疗文档结构化提取专家。根据文档分类结果和原文内容，提取结构化临床数据。\n\n## 上游分类结果\n{classify_result_tks}\n\n## 输出格式\n\n严格输出纯 JSON，禁止使用 ```json 代码块包裹，禁止输出任何非 JSON 文字。\n\n**多记录规则：**\n- 如果原文只包含 1 条记录：输出单个 JSON 对象\n- 如果原文包含多条独立记录（由不同的就诊时间/收款日期标识）：输出 JSON 数组，每个元素为一条记录的完整提取结果，并增加 \"encounter_date\" 字段标识该条记录的日期\n\n## 提取规则\n\n根据分类结果中的 type 字段，按以下 schema 提取：\n\n### OutpatientRecord / AdmissionRecord / DischargeRecord\n{\n  \"encounter_date\": \"<string|null, 该条记录的就诊日期 YYYY-MM-DD, 多记录时必填>\",\n  \"chief_complaint\": \"<string|null, 主诉>\",\n  \"present_illness\": \"<string|null, 现病史，保留完整用药史、剂量、频次>\",\n  \"past_history\": \"<string|null, 既往史>\",\n  \"diagnosis\": \"<string|null, 诊断，保留中西医双诊断>\",\n  \"treatment_plan\": \"<string|object|array|null, 治疗方案，保留药品名+剂量+频次+给药途径>\"\n}\n\n### LabReport / ExamReport / ImagingReport\n{\n  \"report_date\": \"<string|null, 报告日期 YYYY-MM-DD>\",\n  \"items\": [\n    {\n      \"name\": \"<string, 检验项目名称>\",\n      \"value\": \"<string, 结果数值，原样保留>\",\n      \"unit\": \"<string|null, 单位>\",\n      \"reference_range\": \"<string|null, 参考范围>\",\n      \"abnormal\": \"<boolean, 是否异常>\"\n    }\n  ]\n}\n\n### MedicationRecord\n{\n  \"encounter_date\": \"<string|null, 该条记录的购药/处方日期 YYYY-MM-DD, 多记录时必填>\",\n  \"medications\": [\n    {\n      \"name\": \"<string, 药品名称，含商品名>\",\n      \"dosage\": \"<string|null, 单次剂量>\",\n      \"frequency\": \"<string|null, 给药频次>\",\n      \"route\": \"<string|null, 给药途径>\",\n      \"start_date\": \"<string|null, 开始日期 YYYY-MM-DD>\"\n    }\n  ]\n}\n\n### Other\n{\n  \"content_summary\": \"<string, 内容摘要>\"\n}\n\n## 关键约束\n1. 所有提取字段的值必须来源于原文，禁止编造原文中不存在的信息\n2. 原文中不存在的字段填 null，不要猜测\n3. 数值必须原样保留（如\"44.00\"不要改为\"44\"）\n4. OCR 扫描件可能有识别错误，遇到明显 OCR 错字可纠正（如\"益风湿\"→\"类风湿\"）\n5. 如果原文包含多条药品记录或多张购药凭证，必须全部逐条提取到 medications 数组中，不得遗漏\n6. 如果原文包含多次就诊记录（由不同的\"就诊时间\"或\"收款日期\"标识），必须逐条提取每次就诊的完整信息，不得遗漏任何一次。每条记录作为数组中的独立元素输出\n7. 诊断列表必须按原文顺序逐条完整提取，不得遗漏、不得合并、不得调整顺序\n\n## 示例：多次门诊记录\n\n上游分类：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-09-12\", \"2023-09-26\"], \"department\": \"内科门诊\"}\n\n输出：\n[\n  {\n    \"encounter_date\": \"2023-09-12\",\n    \"chief_complaint\": \"膝关节，腕关节疼痛2周余\",\n    \"present_illness\": \"患者自述3年前无明显诱因下出现多关节肿痛，于外院就诊后确诊为类风湿性关节炎，遵医嘱接受中药治疗，然治疗效果不佳，为寻求进一步治疗，今来本院治疗，愿意接受注射阿达木单抗注射液进行治疗\",\n    \"past_history\": \"无传染病，无药物过敏史\",\n    \"diagnosis\": \"西医：类风湿性关节炎 中医：痹症\",\n    \"treatment_plan\": \"阿达木单抗注射液（泰博维-40mg*0.8ml）0.8ml SC 每二周一次 1盒\"\n  },\n  {\n    \"encounter_date\": \"2023-09-26\",\n    \"chief_complaint\": \"类风湿性关节炎复查\",\n    \"present_illness\": \"患者二周前于我院接受阿达木单抗注射液治疗，今来我院就诊复查，并接受第二针治疗\",\n    \"past_history\": \"无传染病，无药物过敏史\",\n    \"diagnosis\": \"西医：类风湿性关节炎 中医：痹症\",\n    \"treatment_plan\": \"阿达木单抗注射液（泰博维-40mg*0.8ml）0.8ml SC 每二周一次 1盒\"\n  }\n]\n\n## 示例：多次购药记录\n\n上游分类：{\"type\": \"MedicationRecord\", \"record_count\": 2, \"encounter_dates\": [\"2024-09-08\", \"2024-10-28\"], \"department\": null}\n\n输出：\n[\n  {\n    \"encounter_date\": \"2024-09-08\",\n    \"medications\": [\n      {\"name\": \"甲氨蝶呤片（信宜平）\", \"dosage\": \"10mg\", \"frequency\": \"每周一次\", \"route\": \"口服\", \"start_date\": \"2024-09-08\"},\n      {\"name\": \"塞来昔布胶囊\", \"dosage\": \"0.2g\", \"frequency\": \"每天一次\", \"route\": \"口服\", \"start_date\": \"2024-09-08\"}\n    ]\n  },\n  {\n    \"encounter_date\": \"2024-10-28\",\n    \"medications\": [\n      {\"name\": \"甲氨蝶呤片（信宜平）\", \"dosage\": \"10mg\", \"frequency\": \"每周一次\", \"route\": \"口服\", \"start_date\": \"2024-10-28\"},\n      {\"name\": \"塞来昔布胶囊\", \"dosage\": \"0.2g\", \"frequency\": \"每天一次\", \"route\": \"口服\", \"start_date\": \"2024-10-28\"}\n    ]\n  }\n]", "temperature": 0.1, "top_p": 0.3}}, "downstream": ["Tokenizer:MedEmbed"], "upstream": ["Extractor:Classify"]}, "Tokenizer:MedEmbed": {"obj": {"component_name": "Tokenizer", "params": {"fields": ["text"], "filename_embd_weight": 0.1, "outputs": {}, "search_method": ["full_text", "embedding"]}}, "downstream": [], "upstream": ["Extractor:Extract"]}}, "globals": {}, "graph": {"nodes": [{"data": {"label": "File", "name": "File"}, "id": "File", "measured": {"width": 200, "height": 50}, "position": {"x": 50, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "beginNode"}, {"data": {"form": {"outputs": {"html": {"type": "string", "value": ""}, "json": {"type": "Array<object>", "value": []}, "markdown": {"type": "string", "value": ""}, "text": {"type": "string", "value": ""}}, "setups": [{"fileFormat": "pdf", "output_format": "json", "parse_method": "DeepDOC"}, {"fileFormat": "spreadsheet", "output_format": "html", "parse_method": "DeepDOC"}, {"fileFormat": "image", "output_format": "text", "parse_method": "ocr"}, {"fileFormat": "word", "output_format": "json"}, {"fileFormat": "slides", "output_format": "json", "parse_method": "DeepDOC"}, {"fileFormat": "text&markdown", "output_format": "text"}, {"fields": ["from", "to", "cc", "bcc", "date", "subject", "body", "attachments"], "fileFormat": "email", "output_format": "text"}]}, "label": "Parser", "name": "Parser_0"}, "id": "Parser:MedLink", "measured": {"width": 200, "height": 198}, "position": {"x": 320, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "parserNode"}, {"data": {"form": {"children_delimiters": [], "chunk_token_size": 1024, "delimiters": ["\n"], "enable_children": false, "image_table_context_window": 0, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "overlapped_percent": 0}, "label": "Splitter", "name": "Splitter_0"}, "id": "Splitter:MedLink", "measured": {"width": 200, "height": 74}, "position": {"x": 590, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "splitterNode"}, {"data": {"form": {"cite": true, "field_name": "classify_result_tks", "frequency_penalty": 0.7, "llm_id": "deepseek-v3.2", "max_tokens": 256, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "presence_penalty": 0.4, "prompts": "{Splitter:MedLink@chunks}", "sys_prompt": "你是一个医疗文档分类专家。根据以下医疗文档片段，提取文档类型、就诊日期和科室信息。\n\n## 输出格式\n\n严格输出纯 JSON，禁止使用 ```json 代码块包裹，禁止输出任何非 JSON 文字。\n\n## JSON Schema\n\n{\n  \"type\": \"<string, 必填, 枚举值见下方>\",\n  \"record_count\": <integer, 该片段中包含的独立记录条数>,\n  \"encounter_dates\": [\"<YYYY-MM-DD>\", ...],\n  \"department\": \"<string|null, 就诊科室>\"\n}\n\n## type 枚举值（必须使用英文值，禁止使用中文）\n\n- OutpatientRecord — 门诊病历（含复诊记录）\n- AdmissionRecord — 入院记录\n- DischargeRecord — 出院小结/出院记录\n- LabReport — 检验报告（血常规、生化、免疫等）\n- ExamReport — 检查报告（心电图、B超等）\n- ImagingReport — 影像报告（X光、CT、MRI等）\n- SurgeryRecord — 手术记录\n- MedicationRecord — 用药记录/处方/购药凭证/取药单\n- NursingRecord — 护理记录\n- Other — 无法归类的文档（如纯收费票据、广告等）\n\n## 字段提取规则\n\n1. record_count：统计片段中包含的独立记录条数。每个独立的就诊时间、检验报告、购药凭证算一条。仔细查找所有\"就诊时间\"、\"收款日期\"等标记来计数。\n2. encounter_dates：提取所有独立记录的日期，格式 YYYY-MM-DD，按时间顺序排列。如果某条记录无日期则跳过该条。\n3. department：提取科室名称。无法确定则填 null。\n\n## 示例\n\n输入：济宁市第二人民医院 门（急）诊病历 就诊时间：2023年09月12日 就诊科室：内科门诊 主诉：膝关节疼痛 ...医生签名：xxx 济宁市第二人民医院 门（急）诊病历 就诊时间：2023年09月26日 就诊科室：内科门诊 主诉：类风湿性关节炎复查\n输出：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-09-12\", \"2023-09-26\"], \"department\": \"内科门诊\"}\n\n输入：菏泽市定陶区人民医院检验报告单 血沉 44.00 mm/h 0~20\n输出：{\"type\": \"LabReport\", \"record_count\": 1, \"encounter_dates\": [], \"department\": null}\n\n输入：幸福人大药房 收款日期：2024-09-08 甲氨蝶呤片 2.5mg*16片 67.0元 ...购药凭证 收款日期：2024-10-28 甲氨蝶呤片 2.5mg*16片 67.0元\n输出：{\"type\": \"MedicationRecord\", \"record_count\": 2, \"encounter_dates\": [\"2024-09-08\", \"2024-10-28\"], \"department\": null}\n\n输入：济宁市第二人民医院 门（急）诊病历 就诊时间：2023年10月10日 就诊科室：内科门诊 主诉：类风湿性关节炎复查 ...医生签名：xxx 就诊时间：2023年10月24日 就诊科室：内科门诊 主诉：类风湿性关节炎复查 ...医生签名：xxx\n输出：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-10-10\", \"2023-10-24\"], \"department\": \"内科门诊\"}", "temperature": 0.1, "top_p": 0.3}, "label": "Extractor", "name": "Classify"}, "id": "Extractor:Classify", "measured": {"width": 200, "height": 90}, "position": {"x": 860, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "contextNode"}, {"data": {"form": {"cite": true, "field_name": "extracted_data_tks", "frequency_penalty": 0.7, "llm_id": "qwen3-max", "max_tokens": 2048, "outputs": {"chunks": {"type": "Array<Object>", "value": []}}, "presence_penalty": 0.4, "prompts": "{Extractor:Classify@chunks}", "sys_prompt": "你是一个医疗文档结构化提取专家。根据文档分类结果和原文内容，提取结构化临床数据。\n\n## 上游分类结果\n{classify_result_tks}\n\n## 输出格式\n\n严格输出纯 JSON，禁止使用 ```json 代码块包裹，禁止输出任何非 JSON 文字。\n\n**多记录规则：**\n- 如果原文只包含 1 条记录：输出单个 JSON 对象\n- 如果原文包含多条独立记录（由不同的就诊时间/收款日期标识）：输出 JSON 数组，每个元素为一条记录的完整提取结果，并增加 \"encounter_date\" 字段标识该条记录的日期\n\n## 提取规则\n\n根据分类结果中的 type 字段，按以下 schema 提取：\n\n### OutpatientRecord / AdmissionRecord / DischargeRecord\n{\n  \"encounter_date\": \"<string|null, 该条记录的就诊日期 YYYY-MM-DD, 多记录时必填>\",\n  \"chief_complaint\": \"<string|null, 主诉>\",\n  \"present_illness\": \"<string|null, 现病史，保留完整用药史、剂量、频次>\",\n  \"past_history\": \"<string|null, 既往史>\",\n  \"diagnosis\": \"<string|null, 诊断，保留中西医双诊断>\",\n  \"treatment_plan\": \"<string|object|array|null, 治疗方案，保留药品名+剂量+频次+给药途径>\"\n}\n\n### LabReport / ExamReport / ImagingReport\n{\n  \"report_date\": \"<string|null, 报告日期 YYYY-MM-DD>\",\n  \"items\": [\n    {\n      \"name\": \"<string, 检验项目名称>\",\n      \"value\": \"<string, 结果数值，原样保留>\",\n      \"unit\": \"<string|null, 单位>\",\n      \"reference_range\": \"<string|null, 参考范围>\",\n      \"abnormal\": \"<boolean, 是否异常>\"\n    }\n  ]\n}\n\n### MedicationRecord\n{\n  \"encounter_date\": \"<string|null, 该条记录的购药/处方日期 YYYY-MM-DD, 多记录时必填>\",\n  \"medications\": [\n    {\n      \"name\": \"<string, 药品名称，含商品名>\",\n      \"dosage\": \"<string|null, 单次剂量>\",\n      \"frequency\": \"<string|null, 给药频次>\",\n      \"route\": \"<string|null, 给药途径>\",\n      \"start_date\": \"<string|null, 开始日期 YYYY-MM-DD>\"\n    }\n  ]\n}\n\n### Other\n{\n  \"content_summary\": \"<string, 内容摘要>\"\n}\n\n## 关键约束\n1. 所有提取字段的值必须来源于原文，禁止编造原文中不存在的信息\n2. 原文中不存在的字段填 null，不要猜测\n3. 数值必须原样保留（如\"44.00\"不要改为\"44\"）\n4. OCR 扫描件可能有识别错误，遇到明显 OCR 错字可纠正（如\"益风湿\"→\"类风湿\"）\n5. 如果原文包含多条药品记录或多张购药凭证，必须全部逐条提取到 medications 数组中，不得遗漏\n6. 如果原文包含多次就诊记录（由不同的\"就诊时间\"或\"收款日期\"标识），必须逐条提取每次就诊的完整信息，不得遗漏任何一次。每条记录作为数组中的独立元素输出\n7. 诊断列表必须按原文顺序逐条完整提取，不得遗漏、不得合并、不得调整顺序\n\n## 示例：多次门诊记录\n\n上游分类：{\"type\": \"OutpatientRecord\", \"record_count\": 2, \"encounter_dates\": [\"2023-09-12\", \"2023-09-26\"], \"department\": \"内科门诊\"}\n\n输出：\n[\n  {\n    \"encounter_date\": \"2023-09-12\",\n    \"chief_complaint\": \"膝关节，腕关节疼痛2周余\",\n    \"present_illness\": \"患者自述3年前无明显诱因下出现多关节肿痛，于外院就诊后确诊为类风湿性关节炎，遵医嘱接受中药治疗，然治疗效果不佳，为寻求进一步治疗，今来本院治疗，愿意接受注射阿达木单抗注射液进行治疗\",\n    \"past_history\": \"无传染病，无药物过敏史\",\n    \"diagnosis\": \"西医：类风湿性关节炎 中医：痹症\",\n    \"treatment_plan\": \"阿达木单抗注射液（泰博维-40mg*0.8ml）0.8ml SC 每二周一次 1盒\"\n  },\n  {\n    \"encounter_date\": \"2023-09-26\",\n    \"chief_complaint\": \"类风湿性关节炎复查\",\n    \"present_illness\": \"患者二周前于我院接受阿达木单抗注射液治疗，今来我院就诊复查，并接受第二针治疗\",\n    \"past_history\": \"无传染病，无药物过敏史\",\n    \"diagnosis\": \"西医：类风湿性关节炎 中医：痹症\",\n    \"treatment_plan\": \"阿达木单抗注射液（泰博维-40mg*0.8ml）0.8ml SC 每二周一次 1盒\"\n  }\n]\n\n## 示例：多次购药记录\n\n上游分类：{\"type\": \"MedicationRecord\", \"record_count\": 2, \"encounter_dates\": [\"2024-09-08\", \"2024-10-28\"], \"department\": null}\n\n输出：\n[\n  {\n    \"encounter_date\": \"2024-09-08\",\n    \"medications\": [\n      {\"name\": \"甲氨蝶呤片（信宜平）\", \"dosage\": \"10mg\", \"frequency\": \"每周一次\", \"route\": \"口服\", \"start_date\": \"2024-09-08\"},\n      {\"name\": \"塞来昔布胶囊\", \"dosage\": \"0.2g\", \"frequency\": \"每天一次\", \"route\": \"口服\", \"start_date\": \"2024-09-08\"}\n    ]\n  },\n  {\n    \"encounter_date\": \"2024-10-28\",\n    \"medications\": [\n      {\"name\": \"甲氨蝶呤片（信宜平）\", \"dosage\": \"10mg\", \"frequency\": \"每周一次\", \"route\": \"口服\", \"start_date\": \"2024-10-28\"},\n      {\"name\": \"塞来昔布胶囊\", \"dosage\": \"0.2g\", \"frequency\": \"每天一次\", \"route\": \"口服\", \"start_date\": \"2024-10-28\"}\n    ]\n  }\n]", "temperature": 0.1, "top_p": 0.3}, "label": "Extractor", "name": "Extract"}, "id": "Extractor:Extract", "measured": {"width": 200, "height": 90}, "position": {"x": 1130, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "contextNode"}, {"data": {"form": {"fields": ["text"], "filename_embd_weight": 0.1, "outputs": {}, "search_method": ["full_text", "embedding"]}, "label": "Tokenizer", "name": "Tokenizer_0"}, "id": "Tokenizer:MedEmbed", "measured": {"width": 200, "height": 114}, "position": {"x": 1670, "y": 200}, "sourcePosition": "right", "targetPosition": "left", "type": "tokenizerNode"}], "edges": [{"id": "xy-edge__Filestart-Parser:MedLinkend", "source": "File", "sourceHandle": "start", "target": "Parser:MedLink", "targetHandle": "end"}, {"id": "xy-edge__Parser:MedLinkstart-Splitter:MedLinkend", "source": "Parser:MedLink", "sourceHandle": "start", "target": "Splitter:MedLink", "targetHandle": "end"}, {"id": "xy-edge__Splitter:MedLinkstart-Extractor:Classifyend", "source": "Splitter:MedLink", "sourceHandle": "start", "target": "Extractor:Classify", "targetHandle": "end"}, {"id": "xy-edge__Extractor:Classifystart-Extractor:Extractend", "source": "Extractor:Classify", "sourceHandle": "start", "target": "Extractor:Extract", "targetHandle": "end"}, {"id": "xy-edge__Extractor:Extractstart-Tokenizer:MedEmbedend", "source": "Extractor:Extract", "target": "Tokenizer:MedEmbed", "sourceHandle": "start", "targetHandle": "end", "type": "buttonEdge"}]}, "history": [], "messages": [], "path": [], "retrieval": [], "variables": {}}', false);
INSERT INTO "user_canvas_version" ("id", "create_time", "create_date", "update_time", "update_date", "user_canvas_id", "title", "description", "dsl", "release") VALUES ('e732f5bc1dff11f19b272a5fbb884ed3', 1773312035794, '2026-03-12T18:40:35'::timestamp, 1773312035794, '2026-03-12T18:40:35'::timestamp, '192c7f7898814e99a34a856ce567a57c', 'Pipeline v3.0 SmartSplitter_2026_03_12_18_40_35', NULL, '{"components": {"File": {"obj": {"component_name": "File", "params": {}}, "downstream": ["Parser:MedLink"], "upstream": []}, "Parser:MedLink": {"obj": {"component_name": "Parser", "params": {"outputs": {"html": {"type": "string", "value": ""}, "json": {"type": "Array<object>", "value": []}, "markdown": {"type": "string", "value": ""}, "text": {"type": "string", "value": ""}}, "setups": {"pdf": {"output_format": "json", "suffix": ["pdf"], "parse_method": "DeepDOC"}, "spreadsheet": {"output_format": "html", "suffix": ["xls", "xlsx", "csv"], "parse_method": "DeepDOC"}, "image": {"output_format": "text", "suffix": ["jpg", "jpeg", "png", "gif"], "parse_method": "ocr"}, "word": {"output_format": "json", "suffix": ["doc", "docx"]}, "slides": {"output_format": "json", "suffix": ["pptx", "ppt"], "parse_method": "DeepDOC"}, "text&markdown": {"output_format": "text", "suffix": ["md", "markdown", "mdx", "txt"]}, "email": {"output_format": "text", "suffix": ["eml", "msg"], "fields": ["from", "to", "cc", "bcc", "date", "subject", "body", "attachments"]}}}}, "downstream": ["SmartSplitter:MedLink"], "upstream": ["File"]}, "Tokenizer:MedEmbed": {"obj": {"component_name": "Tokenizer", "params": {"fields": ["text"], "filename_embd_weight": 0.1, "outputs": {}, "search_method": ["full_text", "embedding"]}}, "downstream": ["Invoke:SyncChunks"], "upstream": ["ChunkMerger:Merger"]}, "ChunkRouter:Router": {"obj": {"component_name": "ChunkRouter", "params": {"classify_field": "classify_result_tks", "default_route": "chunks_Default", "route_map": {"AdmissionRecord": "chunks_Clinical", "DischargeRecord":