5f6\u6709\u95e8\u8bca\u75c5\u5386+\u68c0\u9a8c\u6570\u636e/\u8d2d\u836f\u51ed\u8bc1\uff0c\u4ee5\u95e8\u8bca\u75c5\u5386\u4e3a\u4e3b\u5206\u7c7b\n\n### PrescriptionRecord\uff08\u5904\u65b9\u7528\u836f/\u53d6\u836f\u6267\u884c\u5355\uff09\n\u533b\u9662\u5f00\u5177\u7684\u5904\u65b9\u6216\u53d6\u836f\u6267\u884c\u5355\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u6709\u5c31\u8bca\u79d1\u5ba4 + \u5c31\u8bca\u533b\u751f + \u75be\u75c5\u8bca\u65ad + \u836f\u54c1\u7528\u6cd5\u7528\u91cf\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662 \u53d6\u836f\u6267\u884c\u5355\"\u5f00\u5934\uff0c\u6216\u9644\u5e26\u5fae\u4fe1/\u652f\u4ed8\u5b9d\u4ed8\u6b3e\u622a\u56fe\n- \u5305\u542b\uff1a\u5c31\u8bca\u79d1\u5ba4\u3001\u5c31\u8bca\u533b\u751f\u3001\u8bca\u65ad\u3001\u836f\u54c1\u540d\u79f0\u3001\u5242\u91cf\u3001\u9891\u6b21\u3001\u7ed9\u836f\u9014\u5f84\n- \u6bcf\u5f20\u72ec\u7acb\u7684\u53d6\u836f\u6267\u884c\u5355/\u5904\u65b9\u662f\u4e00\u4e2a\u7247\u6bb5\n\n### MedicationRecord\uff08\u8d2d\u836f\u51ed\u8bc1\uff09\n\u836f\u623f/\u836f\u5e97\u8d2d\u836f\u5c0f\u7968\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u836f\u5e97\u540d\u79f0 + \u836f\u54c1\u6761\u76ee + \u96f6\u552e\u4ef7 + \u5e94\u6536\u91d1\u989d\u3002\n- \u901a\u5e38\u4ee5\"XX\u836f\u5e97/\u836f\u623f \u8d2d\u836f\u51ed\u8bc1\"\u5f00\u5934\n- \u5305\u542b\uff1a\u836f\u5355\u7f16\u53f7\u3001\u6536\u94f6\u5458/\u6b3e\u53f0\u53f7\u3001\u54c1\u540d\u3001\u89c4\u683c\u3001\u96f6\u552e\u4ef7\u3001\u6570\u91cf\u3001\u5e94\u6536\u91d1\u989d\u3001\u5b9e\u6536\u91d1\u989d\n- \u6bcf\u5f20\u72ec\u7acb\u7684\u8d2d\u836f\u51ed\u8bc1/\u5c0f\u7968\u662f\u4e00\u4e2a\u7247\u6bb5\n\n### LabReport\uff08\u68c0\u9a8c\u62a5\u544a\uff09\n\u5b9e\u9a8c\u5ba4\u68c0\u9a8c\u62a5\u544a\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u68c0\u9a8c\u9879\u76ee + \u6570\u503c + \u53c2\u8003\u8303\u56f4\u3002\n- \u901a\u5e38\u4ee5\"XX\u533b\u9662\u68c0\u9a8c\u62a5\u544a\u5355\"\u6216\u76f4\u63a5\u4ee5\u68c0\u9a8c\u9879\u76ee\u8868\u683c\u5f00\u5934\n- \u5305\u542b\u591a\u4e2a\u68c0\u9a8c\u6307\u6807\u548c\u53c2\u8003\u8303\u56f4\n- \u540c\u4e00\u4efd\u62a5\u544a\uff08\u542b\u591a\u9875\uff09\u4e0d\u8981\u62c6\u5f00\n\n### DischargeRecord\uff08\u51fa\u9662\u8bb0\u5f55\uff09\n\u4f4f\u9662\u51fa\u9662\u8bb0\u5f55\u3002\u6838\u5fc3\u7279\u5f81\uff1a\u5165\u9662\u65e5\u671f + \u51fa\u9662\u65e5\u671f + \u51fa\u9662\u8bca\u65ad + \u4f4f\u9662\u7ecf\u8fc7\u3002\n\n## \u8f93\u51fa\u683c\u5f0f\n\u4e25\u683c\u8f93\u51fa\u7eaf JSON \u6570\u7ec4\uff0c\u7981\u6b62 ```json \u4ee3\u7801\u5757\u3002\u6bcf\u4e2a\u5143\u7d20\uff1a\n{\n  \"type\": \"<\u6587\u6863\u7c7b\u578b>\",\n  \"first_line\": \"<\u8be5\u7247\u6bb5\u7b2c\u4e00\u884c\u7684\u524d30\u4e2a\u5b57\u7b26>\",\n  \"last_line\": \"<\u8be5\u7247\u6bb5\u6700\u540e\u4e00\u884c\u7684\u524d30\u4e2a\u5b57\u7b26>\",\n  \"encounter_dates\": [\"YYYY-MM-DD\"],\n  \"department\": \"<\u79d1\u5ba4\u540d\u79f0|null>\",\n  \"record_count\": 1\n}\n\n## \u5207\u5206\u89c4\u5219\n1. \u540c\u4e00\u6b21\u95e8\u8bca\u5c31\u8bca\u8bb0\u5f55\u4e0d\u8981\u62c6\u5f00\uff08\u4ece\"\u5c31\u8bca\u65f6\u95f4\"\u5230\"\u5904\u7406\u610f\u89c1/\u533b\u751f\u7b7e\u540d\"\u662f\u4e00\u4e2a\u5b8c\u6574\u8bb0\u5f55\uff09\n2. \u540c\u4e00\u4efd\u68c0\u9a8c\u62a5\u544a\u4e0d\u8981\u62c6\u5f00\uff08\u542b\u591a\u9875\u8868\u683c\uff09\n3. \u836f\u623f\u8d2d\u836f\u51ed\u8bc1\u548c\u53d6\u836f\u6267\u884c\u5355\u5404\u81ea\u72ec\u7acb\u2014\u2014\u6bcf\u5f20\u7968\u636e/\u6267\u884c\u5355\u4e00\u4e2a\u7247\u6bb5\uff0c\u4e8c\u8005\u662f\u4e0d\u540c\u7684 type\n4. \u51fa\u9662\u8bb0\u5f55\u4e0d\u8981\u62c6\u5f00\n5. \u5982\u679c\u6587\u6863\u672b\u5c3e\u6709\u51e0\u4e2a\u5b57\u7684\u6b8b\u7559\u788e\u7247\uff08<50\u5b57\uff09\uff0c\u5408\u5e76\u5230\u524d\u4e00\u4e2a\u7247\u6bb5\n\n## \u65e5\u671f\u63d0\u53d6\u89c4\u5219\n- \u4ece\u6587\u672c\u4e2d\u63d0\u53d6\u5b9e\u9645\u65e5\u671f\uff0c\u683c\u5f0f YYYY-MM-DD\n- \u5982\u679c\u65e5\u671f\u65e0\u6cd5\u8bc6\u522b\uff08OCR\u635f\u574f\uff09\uff0c\u4f7f\u7528\u7a7a\u6570\u7ec4 []\n- \u4e0d\u8981\u731c