3001\u4ea7\u4e1a\u94fe\u3001\u5b50\u516c\u53f8\u56fe\u8c31\u3001\u63a7\u5236\u94fe\u7a7f\u900f\u3001\u62c5\u4fdd\u94fe\u3001\u5173\u8054\u4ea4\u6613\u3001\u80a1\u4e1c\u53d8\u52a8\u76f8\u5173\u7684\u6240\u6709\u5b9e\u4f53\u548c\u5173\u7cfb\u3002\n\u4f7f\u7528 {language} \u4f5c\u4e3a\u8f93\u51fa\u8bed\u8a00\u3002\n\n---\u80cc\u666f---\n\u4f60\u6b63\u5728\u5206\u6790\u4e2d\u56fdA\u80a1\u4e0a\u5e02\u516c\u53f8\u7684\u5e74\u5ea6\u62a5\u544a\u3002\u8bf7\u91cd\u70b9\u5173\u6ce8\u4ee5\u4e0b\u51e0\u7c7b\u56fe\u8c31\u6307\u6807\uff1a\n\n\u3010\u80a1\u6743\u7ed3\u6784\u3011\n- \u80a1\u4e1c\uff08\u6cd5\u4eba\u80a1\u4e1c\u3001\u81ea\u7136\u4eba\u80a1\u4e1c\u3001\u673a\u6784\u6295\u8d44\u8005\uff09\u53ca\u5176\u6301\u80a1\u6bd4\u4f8b\u3001\u6301\u80a1\u6570\u91cf\n- \u63a7\u80a1\u80a1\u4e1c\u3001\u5b9e\u9645\u63a7\u5236\u4eba\u53ca\u5176\u5b8c\u6574\u63a7\u5236\u94fe\uff08\u81ea\u7136\u4eba\u2192\u63a7\u80a1\u516c\u53f8\u2192\u4e0a\u5e02\u516c\u53f8\uff09\n- \u5b9e\u9645\u63a7\u5236\u4eba\u5fc5\u987b\u8ffd\u6eaf\u5230\u6700\u7ec8\u7684\u81ea\u7136\u4eba\uff08\u5982\"\u515a\u5f66\u5b9d\u6301\u6709XX\u96c6\u56e295%\u80a1\u6743\uff0c\u4e3a\u5b9e\u9645\u63a7\u5236\u4eba\"\uff09\n- \u6cd5\u5b9a\u4ee3\u8868\u4eba\uff1a\u6ce8\u610f\u4e25\u683c\u533a\u5206\u300c\u672c\u4e0a\u5e02\u516c\u53f8\u300d\u7684\u6cd5\u5b9a\u4ee3\u8868\u4eba\u4e0e\u6bcd\u516c\u53f8/\u96c6\u56e2\u7684\u6cd5\u5b9a\u4ee3\u8868\u4eba\uff0c\u53ea\u63d0\u53d6\u672c\u4e0a\u5e02\u516c\u53f8\u7684\n- \u6301\u80a1\u53d8\u52a8\u3001\u589e\u51cf\u6301\u60c5\u51b5\n- \u4e00\u81f4\u884c\u52a8\u4eba\u5173\u7cfb\n\n\u3010\u9ad8\u7ba1\u5173\u8054\u3011\n- \u8463\u4e8b\u4f1a\u5168\u90e8\u6210\u5458\uff08\u6267\u884c\u8463\u4e8b\u3001\u975e\u6267\u884c\u8463\u4e8b\u3001\u72ec\u7acb\u8463\u4e8b\uff09\uff0c\u52a1\u5fc5\u5b8c\u6574\u63d0\u53d6\u6bcf\u4e00\u4f4d\n- \u76d1\u4e8b\u4f1a\u5168\u90e8\u6210\u5458\uff0c\u52a1\u5fc5\u5b8c\u6574\u63d0\u53d6\u6bcf\u4e00\u4f4d\n- \u9ad8\u7ea7\u7ba1\u7406\u4eba\u5458\uff08\u603b\u7ecf\u7406\u3001\u526f\u603b\u7ecf\u7406\u3001\u8d22\u52a1\u603b\u76d1\u3001\u8463\u4e8b\u4f1a\u79d8\u4e66\uff09\n- \u6cd5\u5b9a\u4ee3\u8868\u4eba\uff08\u6ce8\u610f\u662f\u672c\u4e0a\u5e02\u516c\u53f8\u7684\uff0c\u4e0d\u662f\u6bcd\u516c\u53f8\u7684\uff09\n- \u517c\u4efb\u5176\u4ed6\u516c\u53f8\u804c\u52a1\u7684\u60c5\u51b5\n- \u4efb\u804c\u671f\u9650\u548c\u53d8\u52a8\uff08\u65b0\u4efb\u3001\u79bb\u4efb\u3001\u6362\u5c4a\uff09\n- \u4eba\u5458\u7684\u6027\u522b\u3001\u5e74\u9f84\u3001\u5b66\u5386\u7b49\u57fa\u672c\u4fe1\u606f\n\n\u3010\u8d28\u62bc\u98ce\u9669\u3011\n- \"\u80a1\u4efd\u72b6\u6001\"\u5b50\u5217\uff1a\u6807\u6ce8\"\u8d28\u62bc\"\u6216\"\u51bb\u7ed3\"\u6216\"\u6807\u8bb0\"\n- \"\u6570\u91cf\"\u5b50\u5217\uff1a\u5bf9\u5e94\u7684\u80a1\u4efd\u6570\u91cf\n- \u5982\u679c\u8be5\u80a1\u4e1c\u65e0\u8d28\u62bc/\u51bb\u7ed3\uff0c\u6b64\u5217\u4e3a\u7a7a\u6216\u663e\u793a\"\u65e0\"\n- \u4e2d\u5fc3\u8282\u70b9\u4e3a\u4e0a\u5e02\u516c\u53f8\n- \u6bcf\u4e2a\u6709\u8d28\u62bc\u6216\u51bb\u7ed3\u8bb0\u5f55\u7684\u80a1\u4e1c\u4f5c\u4e3a\u5b9e\u4f53\u8282\u70b9\n- \u8fb9\u7684\u63cf\u8ff0\u5fc5\u987b\u5305\u542b\uff1a\u8d28\u62bc/\u51bb\u7ed3\u80a1\u6570\u3001\u6301\u80a1\u603b\u6570\u3001\u8d28\u62bc\u6bd4\u4f8b\n- \u683c\u5f0f\uff1a\"\u8d28\u62bcXXX\u80a1/\u6301\u6709XXX\u80a1/\u8d28\u62bc\u6bd4\u4f8bXX%\"\n- \u6ca1\u6709\u8d28\u62bc\u6216\u51bb\u7ed3\u7684\u80a1\u4e1c\u4e0d\u9700\u8981\u63d0\u53d6\n\n\u3010\u4ea7\u4e1a\u94fe\u3011\n- \u5b50\u516c\u53f8\u3001\u63a7\u80a1\u5b50\u516c\u53f8\u3001\u53c2\u80a1\u516c\u53f8\uff08\u516c\u53f8\u540d\u79f0\u53ca\u6301\u80a1\u6bd4\u4f8b\uff09\n- \u4e3b\u8981\u5ba2\u6237\uff08\u524d\u4e94\u5927\u5ba2\u6237\u540d\u79f0\u53ca\u9500\u552e\u91d1\u989d/\u5360\u6bd4\uff09\n- \u4e3b\u8981\u4f9b\u5e94\u5546\uff08\u524d\u4e94\u5927\u4f9b\u5e94\u5546\u540d\u79f0\u53ca\u91c7\u8d2d\u91d1\u989d/\u5360\u6bd4\uff09\n- \u5408\u8d44/\u5408\u4f5c\u4f01\u4e1a\n- \u6838\u5fc3\u4ea7\u54c1\u548c\u4e1a\u52a1\u7ebf\uff08\u5982\u4e09\u5143\u524d\u9a71\u4f53\u3001\u5de5\u4e1a\u7845\u3001\u7164\u5236\u70ef\u70c3\u7b49\uff0c\u5f52\u7c7b\u4e3a product\uff09\n- \u6838\u5fc3\u6280\u672f\u548c\u6750\u6599\uff08\u5982\u6b63\u6781\u6750\u6599\u3001\u6709\u673a\u7845\u3001\u591a\u6676\u7845\u7b49\uff0c\u5f52\u7c7b\u4e3a product\uff09\n- \u4ea7\u4e1a\u4e0a\u4e0b\u6e38\u5173\u7cfb\uff08\u539f\u6750\u6599\u4f9b\u5e94\u2192\u751f\u4ea7\u2192\u4ea7\u54c1\u9500\u552e\uff09\n\n\u3010\u5b50\u516c\u53f8\u56fe\u8c31\u3011\n- \u6301\u80a1\u6bd4\u4f8b\u5217\u901a\u5e38\u5206\u4e3a\"\u76f4\u63a5\"\u548c\"\u95f4\u63a5\"\u4e24\u4e2a\u5b50\u5217\n- \u6bcf\u4e00\u884c\u4ee3\u8868\u4e00\u4e2a\u7eb3\u5165\u5408\u5e76\u8303\u56f4\u7684\u5b50\u516c\u53f8\n- \u5fc5\u987b\u63d0\u53d6\uff1a\u5b50\u516c\u53f8\u5168\u79f0\u3001\u6301\u80a1\u6bd4\u4f8b\uff08\u533a\u5206\u76f4\u63a5/\u95f4\u63a5\uff09\u3001\u4e1a\u52a1\u6027\u8d28\n- \u8fd9\u91cc\u4f1a\u5217\u51fa\u6700\u91cd\u8981\u7684\u5b50\u516c\u53f8\u7684\u8d22\u52a1\u6570\u636e\n- \u516c\u53f8\u7c7b\u578b\u5217\u4f1a\u6807\u6ce8\"\u5b50\u516c\u53f8\"\u6216\"\u53c2\u80a1\u516c\u53f8\"\n- \"\u672c\u671f\u65b0\u7eb3\u5165\u5408\u5e76\u8303\u56f4\u7684\u4e3b\u4f53\"\u8868\uff1a\u516c\u53f8\u540d\u79f0 | \u80a1\u6743\u53d6\u5f97\u65b9\u5f0f(\u8bbe\u7acb/\u6536\u8d2d) | \u80a1\u6743\u53d6\u5f97\u65f6\u70b9 | \u51fa\u8d44\u989d | \u51fa\u8d44\u6bd4\u4f8b\n- \"\u672c\u671f\u4e0d\u518d\u7eb3\u5165\u5408\u5e76\u8303\u56f4\u7684\u4e3b\u4f53\"\u8868\uff1a\u516c\u53f8\u540d\u79f0 | \u5904\u7f6e\u65b9\u5f0f(\u6ce8\u9500/\u51fa\u552e) | \u5904\u7f6e\u65f6\u70b9\n- \u5b9e\u4f53\u7c7b\u578b\u4ec5\u4fdd\u7559 ORGANIZATION\n- \u4e2d\u5fc3\u8282\u70b9\u4e3a\u4e0a\u5e02\u516c\u53f8\u672c\u8eab\n- \u8fb9\u7684\u63cf\u8ff0\u5fc5\u987b\u5305\u542b\u6301\u80a1\u6bd4\u4f8b\uff0c\u683c\u5f0f\u5982\"\u6301\u80a1100.00%(\u76f4\u63a5)\"\u3001\"\u6301\u80a151%(\u95f4\u63a5)\"\u3001\"\u5168\u8d44\u5b50\u516c\u53f8\"\n- \u5982\u679c\u6709\u591a\u5c42\u6301\u80a1\uff08A\u6301\u6709B\uff0cB\u6301\u6709C\uff09\uff0c\u5fc5\u987b\u4f53\u73b0\u95f4\u63a5\u6301\u80a1\u94fe\u6761\n- \u65b0\u7eb3\u5165\u5408\u5e76\u8303\u56f4\u7684\u5b50\u516c\u53f8\u6807\u6ce8\"\u672c\u671f\u65b0\u8bbe\"\u6216\"\u672c\u671f\u6536\u8d2d\"\n- \u4e0d\u518d\u7eb3\u5165\u7684\u5b50\u516c\u53f8\u6807\u6ce8\"\u672c\u671f\u6ce8\u9500\"\u6216\"\u672c\u671f\u51fa\u552e\"\n\n\u3010\u62c5\u4fdd\u94fe\u3011\n- \u6bcf\u4e00\u884c\u662f\u4e00\u7b14\u5177\u4f53\u7684\u62c5\u4fdd\u8bb0\u5f55\uff0c\u540c\u4e00\u88ab\u62c5\u4fdd\u5bf9\u8c61\u53ef\u80fd\u6709\u591a\u7b14\uff08\u591a\u884c\uff09\n- \u62c5\u4fdd\u7c7b\u578b\u901a\u5e38\u4e3a\"\u8fde\u5e26\u8d23\u4efb\u4fdd\u8bc1\"\n- \u8fd9\u91cc\u662f\u4e0a\u5e02\u516c\u53f8\u4f5c\u4e3a\u88ab\u62c5\u4fdd\u65b9\uff0c\u62c5\u4fdd\u65b9\u4e3a\u63a7\u80a1\u80a1\u4e1c\u3001\u5b9e\u9645\u63a7\u5236\u4eba\u6216\u5173\u8054\u65b9\n- \u62c5\u4fdd\u65b9\u5217\u53ef\u80fd\u5305\u542b\u591a\u4e2a\u4e3b\u4f53\uff08\u7528\u987f\u53f7\u5206\u9694\uff09\uff0c\u5982\"\u672c\u516c\u53f8\u3001\u5408\u76db\u96c6\u56e2\u3001\u7f57\u7acb\u56fd\"\n- \u8fb9\u7684\u65b9\u5411\uff1a\u62c5\u4fdd\u65b9 \u2192(\u62c5\u4fdd)\u2192 \u88ab\u62c5\u4fdd\u65b9\n- \u8fb9\u7684\u63cf\u8ff0\u5fc5\u987b\u5305\u542b\u62c5\u4fdd\u91d1\u989d\uff08\u542b\u5355\u4f4d\u4e07\u5143\uff09\u548c\u62c5\u4fdd\u7c7b\u578b\n- \u4e0a\u5e02\u516c\u53f8\u5bf9\u5b50\u516c\u53f8\u62c5\u4fdd\uff1a\u4e0a\u5e02\u516c\u53f8\u2192\u5b50\u516c\u53f8\n- \u5173\u8054\u65b9\u5bf9\u4e0a\u5e02\u516c\u53f8\u62c5\u4fdd\uff1a\u5173\u8054\u65b9\u2192\u4e0a\u5e02\u516c\u53f8\n- \u591a\u4e2a\u62c5\u4fdd\u65b9\u5171\u540c\u62c5\u4fdd\u7684\uff0c\u6bcf\u4e2a\u62c5\u4fdd\u65b9\u5206\u522b\u5efa\u8fb9\n\n\u3010\u5173\u8054\u4ea4\u6613\u3011\n- \u5355\u4f4d\u901a\u5e38\u4e3a\"\u5143\"\uff08\u4eba\u6c11\u5e01\uff09\n- \u4ea4\u6613\u65b9\u5411\uff1a\u4e0a\u5e02\u516c\u53f8\u4ece\u5173\u8054\u65b9\u91c7\u8d2d\n- \u4ea4\u6613\u65b9\u5411\uff1a\u4e0a\u5e02\u516c\u53f8\u5411\u5173\u8054\u65b9\u9500\u552e/\u63d0\u4f9b\u670d\u52a1\n- \u4e2d\u5fc3\u8282\u70b9\u4e3a\u4e0a\u5e02\u516c\u53f8\n- \u91c7\u8d2d\u4ea4\u6613\uff1a\u4e0a\u5e02\u516c\u53f8 \u2192(\u91c7\u8d2dXX/\u91d1\u989d)\u2192 \u5173\u8054\u65b9\n- \u9500\u552e\u4ea4\u6613\uff1a\u4e0a\u5e02\u516c\u53f8 \u2192(\u9500\u552eXX/\u91d1\u989d)\u2192 \u5173\u8054\u65b9\n- \u79df\u8d41\u4ea4\u6613\uff1a\u6807\u6ce8\u51fa\u79df\u65b9\u2192\u627f\u79df\u65b9\u548c\u79df\u91d1\n- \u8fb9\u7684\u63cf\u8ff0\u5fc5\u987b\u5305\u542b\u4ea4\u6613\u7c7b\u578b\u548c\u91d1\u989d\n\n\u3010\u80a1\u4e1c\u53d8\u52a8\u3011\n- \u7b2c1\u5217\"\u80a1\u4e1c\u540d\u79f0\"\uff1a\u80a1\u4e1c\u7684\u5b8c\u6574\u6cd5\u5b9a\u540d\u79f0\uff08\u6cd5\u4eba\u7528\u5168\u79f0\uff0c\u81ea\u7136\u4eba\u7528\u59d3\u540d\uff09\n- \u7b2c2\u5217\"\u62a5\u544a\u671f\u5185\u589e\u51cf\"\uff1a\u672c\u62a5\u544a\u671f\u51c0\u589e\u51cf\u80a1\u6570\u3002\u6b63\u6570=\u589e\u6301\uff0c\u8d1f\u6570\u6216\u5e26\"-\"=\u51cf\u6301\uff0c\u7a7a\u767d\u6216\"0\"=\u4e0d\u53d8\uff0c\"\u65b0\u8fdb\"=\u672c\u671f\u65b0\u8fdb\u5165\n- \u7b2c3\u5217\"\u671f\u672b\u6301\u80a1\u6570\u91cf\"\uff1a\u671f\u672b\u6301\u6709\u7684\u80a1\u4efd\u603b\u6570\uff08\u5355\u4f4d\uff1a\u80a1\uff09\n- \u7b2c4\u5217\"\u6bd4\u4f8b\"\uff1a\u6301\u80a1\u5360\u603b\u80a1\u672c\u7684\u767e\u5206\u6bd4\n- \u7b2c5\u5217\"\u6709\u9650\u552e\u6761\u4ef6\u80a1\u4efd\u6570\u91cf\"\uff1a\u88ab\u9501\u5b9a\u4e0d\u80fd\u6d41\u901a\u7684\u80a1\u4efd\u6570\n- \u7b2c6\u5217\"\u8d28\u62bc\u3001\u6807\u8bb0\u6216\u51bb\u7ed3\u60c5\u51b5\"\uff1a\u5206\u4e24\u4e2a\u5b50\u5217\u2014\u2014\"\u80a1\u4efd\u72b6\u6001\"(\u8d28\u62bc/\u51bb\u7ed3)\u548c\"\u6570\u91cf\"\n- \u7b2c7\u5217\"\u80a1\u4e1c\u6027\u8d28\"\uff1a\u5982\"\u5883\u5185\u975e\u56fd\u6709\u6cd5\u4eba\"\u3001\"\u5883\u5185\u81ea\u7136\u4eba\"\u3001\"\u5883\u5916\u6cd5\u4eba\"\n- \u4e2d\u5fc3\u8282\u70b9\u4e3a\u4e0a\u5e02\u516c\u53f8\n- \u6bcf\u4e2a\u524d\u5341\u5927\u80a1\u4e1c\u4f5c\u4e3a\u4e00\u4e2a\u5b9e\u4f53\u8282\u70b9\n- \u8fb9\u7684\u63cf\u8ff0\u5fc5\u987b\u5305\u542b\uff1a\u671f\u672b\u6301\u80a1\u6570\u91cf\u3001\u6301\u80a1\u6bd4\u4f8b\u3001\u62a5\u544a\u671f\u5185\u589e\u51cf\n- \u683c\u5f0f\uff1a\"\u6301\u6709XXX\u80a1/XX%/\u589e\u6301(\u6216\u51cf\u6301\u6216\u4e0d\u53d8)XXX\u80a1\"\n- \u80a1\u4e1c\u6027\u8d28\u4f5c\u4e3a\u5b9e\u4f53\u63cf\u8ff0\u7684\u4e00\u90e8\u5206\n\n\u26a0\ufe0f \u63d0\u53d6\u8981\u6c42\u4e0e\u53cd\u4f8b\uff08\u8bf7\u4e25\u683c\u9075\u5b88\uff09\uff1a\n\n\u2705 \u6b63\u786e\u63d0\u53d6\u793a\u4f8b\uff1a\n\u539f\u6587\uff1a\"\u5b81\u590f\u5b9d\u4e30\u96c6\u56e2\u6709\u9650\u516c\u53f8\u6301\u80a135.65%\uff0c\u4e3a\u516c\u53f8\u63a7\u80a1\u80a1\u4e1c\u3002\u515a\u5f66\u5b9d\u6301\u6709\u5b9d\u4e30\u96c6\u56e295.59%\u7684\u80a1\u6743\uff0c\u4e3a\u5b9e\u9645\u63a7\u5236\u4eba\u3002\"\n\u2192 (\"entity\"<|>\u5b81\u590f\u5b9d\u4e30\u96c6\u56e2\u6709\u9650\u516c\u53f8<|>organization<|>\u6301\u80a135.65%\uff0c\u4e3a\u516c\u53f8\u63a7\u80a1\u80a1\u4e1c)\n\u2192 (\"entity\"<|>\u515a\u5f66\u5b9d<|>person<|>\u6301\u6709\u5b9d\u4e30\u96c6\u56e295.59%\u7684\u80a1\u6743\uff0c\u4e3a\u5b9e\u9645\u63a7\u5236\u4eba)\n\u2192 (\"relationship\"<|>\u515a\u5f66\u5b9d<|>\u5b81\u590f\u5b9d\u4e30\u96c6\u56e2\u6709\u9650\u516c\u53f8<|>\u6301\u670995.59%\u80a1\u6743<|>\u6301\u80a1,\u5b9e\u9645\u63a7\u5236<|>10)\n\n\u274c \u9519\u8bef\u63d0\u53d6\u53cd\u4f8b\uff08\u4ee5\u4e0b\u4e0d\u5e94\u63d0\u53d6\u4e3a\u5b9e\u4f53\uff09\uff1a\n- \"\u63a7\u80a1\u80a1\u4e1c\"\"\u5b9e\u9645\u63a7\u5236\u4eba\"\"\u516c\u53f8\u8d1f\u8d23\u4eba\" \u2192 \u8fd9\u4e9b\u662f\u89d2\u8272/\u6cdb\u79f0\uff0c\u4e0d\u662f\u5177\u4f53\u4eba\u540d\u6216\u516c\u53f8\u540d\n- \"\u8463\u4e8b\u4f1a\"\"\u76d1\u4e8b\u4f1a\"\"\u80a1\u4e1c\u5927\u4f1a\"\"\u524d\u5341\u5927\u80a1\u4e1c\" \u2192 \u8fd9\u4e9b\u662f\u6cbb\u7406\u673a\u6784\u6cdb\u79f0\n- \"\u672c\u516c\u53f8\"\"\u672c\u96c6\u56e2\"\"\u5b50\u516c\u53f8\"\"\u4e0a\u5e02\u516c\u53f8\" \u2192 \u8fd9\u4e9b\u662f\u4ee3\u8bcd\u5f0f\u6cdb\u79f0\n- \"\u9012\u5ef6\u6536\u76ca\"\"\u5e94\u6536\u8d26\u6b3e\"\"\u5728\u5efa\u5de5\u7a0b\"\"\u56fa\u5b9a\u8d44\u4ea7\" \u2192 \u8fd9\u4e9b\u662f\u4f1a\u8ba1\u79d1\u76ee\n- \"\u7b2cX\u5c4a\u8463\u4e8b\u4f1a\u7b2cX\u6b21\u4f1a\u8bae\" \u2192 \u8fd9\u662f\u4f1a\u8bae\u540d\u79f0\n- \"\u4f9b\u5e94\u55461\"\"\u5ba2\u6237\u4e00\" \u2192 \u8fd9\u4e9b\u662f\u533f\u540d\u5360\u4f4d\u7b26\n- \"\u59d3\u540d\"\"\u804c\u52a1\"\"\u6bd4\u4f8b\"\"\u91d1\u989d\" \u2192 \u8fd9\u4e9b\u662f\u8868\u683c\u5217\u540d\n- \"\u8463\u4e8b\"\"\u76d1\u4e8b\"\"\u72ec\u7acb\u8463\u4e8b\"\"\u7ba1\u7406\u4eba\u5458\"\"\u9500\u552e\u4eba\u5458\" \u2192 \u8fd9\u4e9b\u662f\u89d2\u8272/\u804c\u4f4d\u7c7b\u522b\u8bcd\uff0c\u4e0d\u662f\u5177\u4f53\u4eba\u540d\u3002\u5e94\u63d0\u53d6\u5177\u4f53\u4eba\u540d\u5982\"\u5218\u5143\u7ba1\"\uff0c\u800c\u975e\u89d2\u8272\u8bcd\n- \"\u5168\u4f53\u76d1\u4e8b\"\"\u8463\u4e8b\u3001\u76d1\u4e8b\u3001\u9ad8\u7ea7\u7ba1\u7406\u4eba\u5458\" \u2192 \u8fd9\u4e9b\u662f\u4eba\u7269\u7fa4\u4f53\u6cdb\u79f0\n- \"\u4e13\u4e1a\u5316\u6280\u672f\u56e2\u961f\"\"\u4e2d\u9ad8\u7ea7\u7ba1\u7406\u56e2\u961f\"\"\u9ad8\u7ba1\u56e2\u961f\" \u2192 \u8fd9\u4e9b\u662f\u56e2\u961f\u96c6\u5408\u540d\u8bcd\n- \"\u5b9e\u9645\u63a7\u5236\u4eba\"\"\u516c\u53f8\u8d1f\u8d23\u4eba\"\"\u6301\u6709\u4eba\" \u2192 \u8fd9\u4e9b\u662f\u89d2\u8272\u6cdb\u79f0\n- \"\u672c\u516c\u53f8\"\"\u672c\u96c6\u56e2\"\"\u5b50\u516c\u53f8\"\"\u8463\u4e8b\u4f1a\" \u2192 \u8fd9\u4e9b\u662f\u6cdb\u6307\u4ee3\u8bcd\u6216\u6cbb\u7406\u673a\u6784\n- \"\u59d3\u540d\"\"\u804c\u52a1\"\"\u4efb\u671f\u8d77\u59cb\u65e5\u671f\"\"\u51fa\u751f\u5e74\u6708\" \u2192 \u8fd9\u4e9b\u662f\u8868\u683c\u5217\u540d\n- \u2705 \u6b63\u786e: (\u5b81\u6ce2\u5408\u76db\u96c6\u56e2\u6709\u9650\u516c\u53f8, \u8d28\u62bc270,846,100\u80a1/\u6301\u6709546,647,073\u80a1/\u8d28\u62bc\u6bd4\u4f8b49.55%, \u5408\u76db\u7845\u4e1a)\n- \u2705 \u6b63\u786e: (\u7f57\u71da, \u8d28\u62bc77,532,300\u80a1/\u6301\u6709192,493,302\u80a1/\u8d28\u62bc\u6bd4\u4f8b40.28%, \u5408\u76db\u7845\u4e1a)\n- \u2705 \u6b63\u786e: (\u7f57\u70e8\u680b, \u8d28\u62bc90,520,000\u80a1/\u6301\u6709179,406,101\